//! Leaf vocabulary types for the ISM attribute model.
//!
//! Houses the structural, generated-CVE, and classification leaf types
//! shared by [`crate::ParsedAttrs`], [`crate::CanonicalAttrs`], and
//! [`crate::ProjectedMarking`]. Mirrors the IC ISM XML attribute model.
//!
//! # Code generation
//! CVE enum variants (`SciControl`, `DissemControl`, `DeclassExemption`) are
//! generated by `build.rs` from ODNI CVE XML files and re-exported from
//! `crate::generated::values`.
//!
//! SAR is NOT code-generated — SAR program identifiers are agency-assigned
//! codewords, not a closed vocabulary. SAR is modeled structurally via
//! [`SarMarking`] / [`SarProgram`] / [`SarCompartment`].
//!
//! # Pivot type history
//!
//! Pre-PR-3a a single owned struct (then named `IsmAttributes`) lived in
//! this module and served both as the parser output and the
//! rule-consumption form. PR 3a split that role across three types:
//!
//! - [`crate::ParsedAttrs`] (in `parsed.rs`) — borrowed parser output.
//! - [`crate::CanonicalAttrs`] (in `canonical.rs`) — owned rule input.
//! - [`crate::ProjectedMarking`] (in `projected.rs`) — page projection
//!   output. Defined at PR 3a; PR 6 wires the engine to consume it.
//!
//! The `from_parsed_unchecked` adapter bridges parser output to
//! `CanonicalAttrs` during the keystone window; PR 3c's
//! `MarkingScheme::canonicalize` replaces it.

use smallvec::SmallVec;
use smol_str::SmolStr;

use crate::generated::values;
use crate::span::Span;

// Re-export generated enum types for convenience.
pub use values::{DeclassExemption, DissemControl, SciControl, SciControlBare};

/// One parser-recognized token plus its byte span in the original source.
///
/// Used by Phase 3 rules to surface byte-precise diagnostic spans without
/// re-parsing the source. The `text` field carries the literal token bytes
/// so rules that need the source content (E006, E007, E008 against migration
/// keys) can look up entries without threading `&[u8] source` through every
/// `Rule::check` signature.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct TokenSpan {
    pub kind: TokenKind,
    pub span: Span,
    pub text: SmolStr,
}

/// Discriminant for `TokenSpan`. Phase 3 rules read these to filter
/// token-span lookups by category.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum TokenKind {
    /// Classification level token (S, SECRET, TS, TOP SECRET, ...).
    Classification,
    /// SCI control token (SI, TK, HCS, ...).
    ///
    /// Emitted by the existing CVE exact-match path. For new structural
    /// parsing (spec 003-sci-compartments) see [`TokenKind::SciSystem`],
    /// [`TokenKind::SciCompartment`], and [`TokenKind::SciSubCompartment`].
    SciControl,
    /// Structural SCI control-system anchor (e.g., `SI`, `TK`, `123`).
    ///
    /// Emitted by the structural SCI parser introduced in spec
    /// 003-sci-compartments alongside the existing [`TokenKind::SciControl`]
    /// token for exact-CVE matches.
    SciSystem,
    /// Structural SCI compartment identifier (e.g., `G` in `SI-G`).
    SciCompartment,
    /// Structural SCI sub-compartment identifier (e.g., `ABCD` in `SI-G ABCD`).
    SciSubCompartment,
    /// Legacy SAR identifier token. Superseded by `SarIndicator` +
    /// `SarProgram` + `SarCompartment` + `SarSubCompartment` after the
    /// structural SAR model landed. No longer emitted by the parser.
    #[deprecated(note = "use SarIndicator/SarProgram/SarCompartment/SarSubCompartment")]
    SarIdentifier,
    /// SAR category indicator — `SAR-` or `SPECIAL ACCESS REQUIRED-`.
    /// One per SAR block; serves as the anchor for block-ordering rules.
    SarIndicator,
    /// SAR program identifier (e.g., `BP`, `BUTTER POPCORN`).
    SarProgram,
    /// SAR compartment identifier (e.g., `J12`).
    SarCompartment,
    /// SAR sub-compartment identifier (e.g., `J54`).
    SarSubCompartment,
    /// Atomic Energy Act marking token (RD, FRD, CNWDI, TFNI, SIGMA ##, etc.).
    AeaMarking,
    /// FGI marker token (`FGI`, `FGI DEU`, `FGI DEU GBR`).
    FgiMarker,
    /// Dissemination control token (NOFORN, NF, ORCON, OC, RELIDO, ...).
    DissemControl,
    /// Non-IC dissemination control token (LIMDIS, DS, SBU, LES, SSI, ...).
    NonIcDissem,
    /// REL TO country trigraph (USA, GBR, AUS, ...). One per token, not the
    /// whole REL TO list.
    RelToTrigraph,
    /// The full `REL TO ...` block text. Recorded so E013 can inspect the
    /// raw source for delimiter errors (spaces instead of commas).
    RelToBlock,
    /// DISPLAY ONLY country trigraph (AFG, IRQ, NATO, ...) — one per
    /// token, not the whole DISPLAY ONLY list. Parallel to
    /// [`Self::RelToTrigraph`]; the per-trigraph span is distinct
    /// from REL TO so future rules that operate on a single axis
    /// (e.g., per-§D.2 Table 3 row 25/26 banner roll-up) can locate
    /// only the relevant entries.
    DisplayOnlyTrigraph,
    /// The full `DISPLAY ONLY ...` block text, including the
    /// `DISPLAY ONLY` keyword and the comma-separated country list.
    /// Parallel to [`Self::RelToBlock`].
    DisplayOnlyBlock,
    /// Declassification exemption code in CAB or banner (25X1, 50X1-HUM).
    DeclassExemption,
    /// Declassification date in CAB or banner (YYYYMMDD or YYYY).
    DeclassDate,
    /// `//` separator between blocks. Recorded so E004 can detect extra/
    /// missing separator runs.
    Separator,
    /// A non-empty block that did not match any known token kind. E008 fires
    /// one diagnostic per `Unknown` entry.
    Unknown,
}

// ===========================================================================
// SAR (Special Access Required) structural types
// ===========================================================================
//
// See CAPCO Register §H.5 (pp 99–102) and §A.6 (pp 15–17) for the source
// grammar. SAR identifiers are agency-assigned codewords and cannot be
// enumerated — this type hierarchy validates shape and roll-up rather than
// membership.

/// Complete SAR category block parsed from a marking.
///
/// Produced by `marque-core::parser::parse_sar_category` (P2) and stored on
/// [`CanonicalAttrs::sar_markings`]. Only one SAR block is permitted per
/// marking per §A.6; multiple `//SAR-…//` blocks in the same marking yield
/// an `E030 sar-indicator-repeat` diagnostic.
#[non_exhaustive]
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SarMarking {
    /// The form of SAR indicator used in the source marking.
    pub indicator: SarIndicator,
    /// Programs in the order they appeared. Sort-order validation is
    /// performed by rule E028, not at parse time.
    pub programs: Box<[SarProgram]>,
}

/// Which SAR indicator form a marking uses. Banner lines may use either;
/// portion marks may only use `Abbrev` (rule E026 enforces this).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SarIndicator {
    /// `SAR-` (portion and banner).
    Abbrev,
    /// `SPECIAL ACCESS REQUIRED-` (banner only).
    Full,
}

/// A single Special Access Program with optional compartments.
///
/// Identifier forms (§A.6 grammar):
/// - Abbreviated: 2–3 alphanumeric characters (`BP`, `CD`, `XR`).
/// - Full (nickname): uppercase letters with optional spaces
///   (`BUTTER POPCORN`).
#[non_exhaustive]
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SarProgram {
    /// Program identifier as it appeared in the source.
    ///
    /// `SmolStr` inline storage is capped at 23 bytes. Abbreviated form
    /// (2–3 chars) and most nicknames stay inline; nicknames above the
    /// threshold (e.g., `SPECIAL ACCESS REQUIRED` is exactly 23 bytes,
    /// anything longer overflows) fall back to `Arc<str>`. The fallback
    /// is still better than `Box<str>`'s always-heap path and keeps
    /// `Clone` cheap (refcount bump), so the field stays `SmolStr` even
    /// for the full-form case.
    pub identifier: SmolStr,
    /// Compartments in source order. May be empty.
    pub compartments: Box<[SarCompartment]>,
}

/// A compartment within a SAR program, optionally carrying sub-compartments.
///
/// §H.5 p100 explicitly forbids depicting hierarchy below the sub-compartment
/// level.
#[non_exhaustive]
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SarCompartment {
    /// Compartment identifier (alphanumeric).
    pub identifier: SmolStr,
    /// Sub-compartments in source order. May be empty.
    pub sub_compartments: Box<[SmolStr]>,
}

impl SarMarking {
    /// Construct a [`SarMarking`] from an indicator form and a list of
    /// programs. `programs` SHOULD be in source order — sort validation is
    /// performed by rule E028, not here.
    pub fn new(indicator: SarIndicator, programs: Box<[SarProgram]>) -> Self {
        Self {
            indicator,
            programs,
        }
    }
}

impl SarProgram {
    /// Construct a [`SarProgram`] with an optional compartment list.
    pub fn new(identifier: impl Into<SmolStr>, compartments: Box<[SarCompartment]>) -> Self {
        Self {
            identifier: identifier.into(),
            compartments,
        }
    }

    /// SAR program identifier abbreviation shape gate: 2 or 3 ASCII
    /// alphanumeric bytes, any case.
    ///
    /// This is the byte-class admission predicate for the `SAR-`
    /// indicator form (the abbreviated, portion-mark-and-banner form).
    /// Parser admission for the `SPECIAL ACCESS REQUIRED-` indicator
    /// form goes through [`SarProgram::admits_program_id_full`]
    /// instead — the full form admits a different shape (uppercase
    /// letters with optional spaces, no length cap).
    ///
    /// # Single source of truth
    ///
    /// This predicate is the canonical SAR abbreviation shape gate.
    /// The `Vocabulary<CapcoScheme>` adapter at
    /// `crates/capco/src/vocabulary.rs` calls this from
    /// `shape_admits(CAT_SAR, _)` (Phase 5 PR-2 gating); the strict
    /// parser at `crates/core/src/parser.rs::parse_sar_program` calls
    /// it directly to gate the `SarIndicator::Abbrev` branch
    /// (FR-015 / FR-016, T089). Both call sites MUST go through this
    /// function rather than inline a length-and-class check —
    /// keeping the predicate single-sited prevents drift between
    /// admission and parser surfaces (CHK030).
    ///
    /// # Authority
    ///
    /// CAPCO-2016 §H.5 p101 ("Additional Marking Instructions: A
    /// program identifier abbreviation is the two or three-character
    /// designator for the program") fixes the length bound.
    /// CAPCO-2016 §H.5 p99 ("SAR program identifiers are
    /// alphanumeric values") fixes the character class.
    ///
    /// SAR is the only marking category with no CVE registry —
    /// `CVEnumISMSAR.xml` is intentionally empty per ODNI policy.
    /// With no registry to validate against, the shape gate IS the
    /// validation. Per CAPCO-2016 §A.6 p15 and §G.1 p36, all
    /// banner-line and portion-mark Register entries are uppercase,
    /// so SAR identifiers must conform. Lenient acceptance would let
    /// lowercase identifiers through the strict path silently,
    /// bypassing the `DecoderRecognizer` that handles demangling
    /// (e.g., mixed-case repair, missing-hyphen suggestions). The
    /// parser/decoder split is intentional: the parser is strict so
    /// the decoder can be lenient and informative.
    ///
    // TODO(decoder): the current SAR INFO message is generic
    // ("you're on your own here"). Enhancing the decoder to emit
    // specific demangling suggestions (e.g., `SAR-BP XA5` →
    // `SAR-BP-XA5` with explicit missing-hyphen diagnostic) is
    // future work tracked separately from this strict-shape fix
    // (issue #280).
    ///
    /// # Examples
    ///
    /// ```
    /// use marque_ism::SarProgram;
    /// // §H.5 p101 examples (Register convention: uppercase).
    /// assert!(SarProgram::admits_program_id_abbrev(b"BP"));
    /// assert!(SarProgram::admits_program_id_abbrev(b"SDA"));
    /// assert!(SarProgram::admits_program_id_abbrev(b"XR"));
    /// // §H.5 p99 — alphanumeric values (digits permitted).
    /// assert!(SarProgram::admits_program_id_abbrev(b"99"));
    /// assert!(SarProgram::admits_program_id_abbrev(b"A1"));
    /// // Rejected: lowercase fails the Register-uppercase rule
    /// // (§A.6 p15 + §G.1 p36); decoder handles demangling.
    /// assert!(!SarProgram::admits_program_id_abbrev(b"bp"));
    /// assert!(!SarProgram::admits_program_id_abbrev(b"Bp"));
    /// // Rejected: too short.
    /// assert!(!SarProgram::admits_program_id_abbrev(b"B"));
    /// // Rejected: too long.
    /// assert!(!SarProgram::admits_program_id_abbrev(b"BPCD"));
    /// // Rejected: empty.
    /// assert!(!SarProgram::admits_program_id_abbrev(b""));
    /// // Rejected: punctuation.
    /// assert!(!SarProgram::admits_program_id_abbrev(b"B-"));
    /// assert!(!SarProgram::admits_program_id_abbrev(b"B P"));
    /// ```
    #[inline]
    pub const fn admits_program_id_abbrev(bytes: &[u8]) -> bool {
        let len = bytes.len();
        if len < 2 || len > 3 {
            return false;
        }
        let mut i = 0;
        while i < len {
            if !(bytes[i].is_ascii_uppercase() || bytes[i].is_ascii_digit()) {
                return false;
            }
            i += 1;
        }
        true
    }

    /// SAR full-form program identifier shape gate: one or more
    /// ASCII bytes, each either an uppercase letter `[A-Z]` or
    /// space, with at least one non-space byte. Hyphens and digits
    /// are NOT permitted inside the full nickname.
    ///
    /// This is the byte-class admission predicate for the
    /// `SPECIAL ACCESS REQUIRED-` indicator form (the spelled-out,
    /// banner-only form). Parser admission for the abbreviated form
    /// (`SAR-`) goes through
    /// [`SarProgram::admits_program_id_abbrev`] instead.
    ///
    /// The hyphen exclusion is load-bearing: in the parser, the
    /// first `-` after the indicator literal always marks the
    /// program/compartment boundary
    /// (CAPCO-2016 §H.5 p100). If the predicate admitted hyphens, a
    /// nickname like `"BUTTER-POPCORN"` would parse as a program
    /// `"BUTTER"` with compartment `"POPCORN"` — silently
    /// reinterpreting the marking. The digit exclusion follows the
    /// Register convention that nicknames spell out program names
    /// (Table 7 §H.5 p100 example: `BUTTER POPCORN`); the digits
    /// belong with the abbreviation form, not the full form.
    ///
    /// # Single source of truth
    ///
    /// The strict parser at
    /// `crates/core/src/parser.rs::parse_sar_program` calls this to
    /// gate the `SarIndicator::Full` branch (FR-015 closure
    /// alongside the abbreviation predicate). The
    /// `Vocabulary<CapcoScheme>::shape_admits(CAT_SAR, _)` arm
    /// gates the *abbreviation* shape (the most common surface
    /// form, and the one a category-level admission predicate is
    /// most useful for); the full form has no `CategoryId` of its
    /// own in the current scheme, so the vocabulary surface does
    /// not call this directly. Keeping the predicate symbolic in
    /// `marque-ism` rather than inline at the parser site preserves
    /// the FR-015 invariant ("admission via documented vocabulary
    /// surface") and matches the FGI / abbreviation precedent.
    ///
    /// # Authority
    ///
    /// CAPCO-2016 §H.5 p101 ("Authorized Banner Line Marking
    /// Title: SPECIAL ACCESS REQUIRED-[program identifier]";
    /// "Example Banner Line: TOP SECRET//SAR-BUTTER POPCORN") +
    /// §H.5 p100 Table 7 (canonical example uses `BUTTER POPCORN`,
    /// uppercase letters with a single interior space).
    ///
    /// CAPCO-2016 does not explicitly bound the full-form character
    /// class beyond "the program's assigned nickname, codeword, or
    /// abbreviation" (§H.5 p99). The "uppercase + spaces, no
    /// hyphens, no digits" interpretation is a marque parser
    /// convention rooted in Table 7's canonical example and the
    /// hyphen-as-compartment-separator rule (§H.5 p100). This is
    /// noted at the call site so a future revision of CAPCO can
    /// widen or narrow the predicate intentionally rather than by
    /// drift.
    ///
    /// # Examples
    ///
    /// ```
    /// use marque_ism::SarProgram;
    /// // §H.5 p101 canonical example.
    /// assert!(SarProgram::admits_program_id_full(b"BUTTER POPCORN"));
    /// // Single uppercase token also lawful.
    /// assert!(SarProgram::admits_program_id_full(b"SODA"));
    /// // Multiple interior spaces are accepted by the predicate;
    /// // a downstream style rule may flag double-spacing.
    /// assert!(SarProgram::admits_program_id_full(b"BUTTER  POPCORN"));
    /// // Rejected: lowercase.
    /// assert!(!SarProgram::admits_program_id_full(b"butter popcorn"));
    /// // Rejected: digits — abbreviation territory.
    /// assert!(!SarProgram::admits_program_id_full(b"123"));
    /// // Rejected: hyphen — would silently re-parse as
    /// // program/compartment boundary.
    /// assert!(!SarProgram::admits_program_id_full(b"BUTTER-POPCORN"));
    /// // Rejected: empty.
    /// assert!(!SarProgram::admits_program_id_full(b""));
    /// // Rejected: only spaces.
    /// assert!(!SarProgram::admits_program_id_full(b"   "));
    /// ```
    #[inline]
    pub const fn admits_program_id_full(bytes: &[u8]) -> bool {
        if bytes.is_empty() {
            return false;
        }
        let mut i = 0;
        let mut has_non_space = false;
        while i < bytes.len() {
            let b = bytes[i];
            if b == b' ' {
                // space — permitted.
            } else if b.is_ascii_uppercase() {
                has_non_space = true;
            } else {
                return false;
            }
            i += 1;
        }
        has_non_space
    }
}

impl SarCompartment {
    /// Construct a [`SarCompartment`] with an optional sub-compartment list.
    pub fn new(identifier: impl Into<SmolStr>, sub_compartments: Box<[SmolStr]>) -> Self {
        Self {
            identifier: identifier.into(),
            sub_compartments,
        }
    }

    /// SAR compartment / sub-compartment identifier shape gate:
    /// one or more ASCII alphanumeric bytes, any case.
    ///
    /// CAPCO-2016 §H.5 pp 99-100 places compartments and
    /// sub-compartments under one rule: both are alphanumeric values
    /// listed in ascending sort order. The grammar does not
    /// distinguish their character class or length bounds, so a
    /// single predicate admits both grammar positions. The parser
    /// (`crates/core/src/parser.rs::parse_sar_program`) calls this
    /// for both the compartment slot and the sub-compartment slot.
    ///
    /// # Single source of truth
    ///
    /// The strict parser at
    /// `crates/core/src/parser.rs::parse_sar_program` calls this to
    /// gate compartments (segments after the first `-`) and
    /// sub-compartments (space-separated tokens within a
    /// compartment segment) (FR-015, T090, T091). Both call sites
    /// MUST go through this function rather than inline a
    /// length-and-class check — keeping the predicate single-sited
    /// prevents drift between admission and parser surfaces
    /// (CHK030).
    ///
    /// The `Vocabulary<CapcoScheme>::shape_admits(CAT_SAR, _)` arm
    /// uses [`SarProgram::admits_program_id_abbrev`] (the
    /// program-id-abbreviation shape) because `CAT_SAR` represents
    /// the SAR program identifier slot in the marking grammar, not
    /// the compartment slot. There is no `CategoryId` for SAR
    /// compartments today; if one is added, this predicate is the
    /// natural target for its `shape_admits` arm.
    ///
    /// # Authority
    ///
    /// CAPCO-2016 §H.5 p99 ("SAR program identifiers are
    /// alphanumeric values"; the surrounding prose at p99-100
    /// applies the same rule to compartments and sub-compartments).
    /// CAPCO-2016 §H.5 p100 Table 7 examples confirm the character
    /// class spans alpha (`J12`, `K15`, `YYY`, `XRA`, `J54`, `RB`)
    /// and digit (`456`, `689`).
    ///
    /// CAPCO-2016 prose does NOT specify an upper length bound for
    /// compartments or sub-compartments — Table 7 examples are 2-3
    /// characters but no rule pins that. We admit length ≥ 1 with
    /// no upper bound, matching the parser's existing behavior. A
    /// future revision of CAPCO that pins a length cap would be a
    /// planned migration; this predicate is the lift point.
    ///
    /// SAR is the only marking category with no CVE registry —
    /// `CVEnumISMSAR.xml` is intentionally empty per ODNI policy.
    /// With no registry to validate against, the shape gate IS the
    /// validation. Per CAPCO-2016 §A.6 p15 and §G.1 p36, all
    /// banner-line and portion-mark Register entries are uppercase,
    /// so SAR identifiers (programs, compartments, sub-compartments)
    /// must conform. Lenient acceptance would let lowercase
    /// identifiers through the strict path silently, bypassing the
    /// `DecoderRecognizer` that handles demangling (e.g.,
    /// mixed-case repair, missing-hyphen suggestions). The
    /// parser/decoder split is intentional: the parser is strict so
    /// the decoder can be lenient and informative.
    ///
    // TODO(decoder): the current SAR INFO message is generic
    // ("you're on your own here"). Enhancing the decoder to emit
    // specific demangling suggestions for compartment / sub-
    // compartment case-mismatches is future work tracked separately
    // from this strict-shape fix (issue #280).
    ///
    /// # Examples
    ///
    /// ```
    /// use marque_ism::SarCompartment;
    /// // §H.5 p100 Table 7 examples.
    /// assert!(SarCompartment::admits_identifier(b"J12"));
    /// assert!(SarCompartment::admits_identifier(b"K15"));
    /// assert!(SarCompartment::admits_identifier(b"YYY"));
    /// assert!(SarCompartment::admits_identifier(b"RB"));
    /// // Sub-compartments use the same shape.
    /// assert!(SarCompartment::admits_identifier(b"J54"));
    /// assert!(SarCompartment::admits_identifier(b"456"));
    /// assert!(SarCompartment::admits_identifier(b"689"));
    /// // Single character is admitted (manual silent on lower bound
    /// // beyond ≥1; marque admits length 1+).
    /// assert!(SarCompartment::admits_identifier(b"1"));
    /// // Rejected: lowercase fails the Register-uppercase rule
    /// // (§A.6 p15 + §G.1 p36); decoder handles demangling.
    /// assert!(!SarCompartment::admits_identifier(b"j12"));
    /// assert!(!SarCompartment::admits_identifier(b"yYy"));
    /// // Rejected: empty.
    /// assert!(!SarCompartment::admits_identifier(b""));
    /// // Rejected: punctuation.
    /// assert!(!SarCompartment::admits_identifier(b"J-12"));
    /// assert!(!SarCompartment::admits_identifier(b"J 12"));
    /// // Rejected: non-ASCII.
    /// assert!(!SarCompartment::admits_identifier("Ĵ12".as_bytes()));
    /// ```
    #[inline]
    pub const fn admits_identifier(bytes: &[u8]) -> bool {
        if bytes.is_empty() {
            return false;
        }
        let mut i = 0;
        while i < bytes.len() {
            if !(bytes[i].is_ascii_uppercase() || bytes[i].is_ascii_digit()) {
                return false;
            }
            i += 1;
        }
        true
    }
}

// ===========================================================================
// Classification types
// ===========================================================================

/// The classification system and level for a marking.
///
/// A marking has exactly one classification system. When the parser finds
/// two (e.g., `SECRET//NATO SECRET//...`), it resolves to [`Conflict`](Self::Conflict).
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum MarkingClassification {
    /// US IC classification.
    Us(Classification),
    /// Non-US (FGI) classification: `//GBR S//...`
    Fgi(FgiClassification),
    /// NATO classification: `//NS//...`
    Nato(NatoClassification),
    /// JOINT classification (US co-owned): `//JOINT S USA GBR//...`
    Joint(JointClassification),
    /// Parser found two classification systems in one marking.
    ///
    /// US wins, upgraded to the greater of the two levels.
    /// The foreign part is preserved so rules can suggest the FGI fix.
    ///
    /// Example: `SECRET//COSMIC TOP SECRET//REL TO USA, NATO`
    /// → `us: TopSecret`, `foreign: Nato(CosmicTopSecret)`
    /// → fix: `TOP SECRET//FGI NATO//REL TO USA, NATO`
    Conflict {
        /// Resolved US classification (max of both levels).
        us: Classification,
        /// The foreign classification that should become an FGI marker.
        foreign: Box<ForeignClassification>,
    },
}

impl MarkingClassification {
    /// The effective classification level for ordering purposes, regardless of
    /// classification system.
    ///
    /// NATO levels are mapped to their US equivalents via
    /// [`NatoClassification::us_equivalent`]. All systems use the
    /// [`Classification`] ladder for comparison so that `Iterator::max()` on
    /// a mixed set of portions returns the most restrictive level overall.
    pub fn effective_level(&self) -> Classification {
        match self {
            Self::Us(c) => *c,
            Self::Fgi(f) => f.level,
            Self::Nato(n) => n.us_equivalent(),
            Self::Joint(j) => j.level,
            Self::Conflict { us, .. } => *us,
        }
    }
}

impl Default for MarkingClassification {
    fn default() -> Self {
        Self::Us(Classification::Unclassified)
    }
}

/// The non-US classification in a [`MarkingClassification::Conflict`].
///
/// Preserves enough information for rules to generate the FGI fix:
/// the foreign system, its level, and any associated countries.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum ForeignClassification {
    Fgi(FgiClassification),
    Nato(NatoClassification),
    Joint(JointClassification),
}

// ---------------------------------------------------------------------------
// Classification level (US ladder + RESTRICTED for foreign interop)
// ---------------------------------------------------------------------------

/// Classification level. Ordered by restrictiveness: U < R < C < S < TS.
///
/// Includes `Restricted` for foreign-origin markings — many non-US
/// classification systems (and NATO) have a RESTRICTED level between
/// UNCLASSIFIED and CONFIDENTIAL.
///
/// The derived `Ord` reflects restrictiveness ordering so that
/// `Iterator::max()` returns the most restrictive level.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum Classification {
    Unclassified,
    Restricted,
    Confidential,
    Secret,
    TopSecret,
}

impl Classification {
    /// Banner form (full words, no abbreviations).
    pub fn banner_str(self) -> &'static str {
        match self {
            Self::Unclassified => "UNCLASSIFIED",
            Self::Restricted => "RESTRICTED",
            Self::Confidential => "CONFIDENTIAL",
            Self::Secret => "SECRET",
            Self::TopSecret => "TOP SECRET",
        }
    }

    /// Portion form (abbreviation used in portion markings).
    pub fn portion_str(self) -> &'static str {
        match self {
            Self::Unclassified => "U",
            Self::Restricted => "R",
            Self::Confidential => "C",
            Self::Secret => "S",
            Self::TopSecret => "TS",
        }
    }
}

// ---------------------------------------------------------------------------
// FGI classification (non-US, country-prefixed)
// ---------------------------------------------------------------------------

/// Non-US (FGI) classification.
///
/// Two forms exist:
///
/// - **Source-acknowledged**: country trigraph(s) identify the originator.
///   `//GBR S//REL TO USA, GBR` (single owner) or `//CAN GBR S` (multiple
///   producers per the §H.7 p123 worked example `(//CAN GBR S)` and §H.7
///   p124 prose authorizing multi-country FGI alphabetically space-
///   separated; ICD 206 commingling clause).
/// - **Source-concealed**: `FGI` replaces the country trigraph(s) when
///   the originating country is sensitive. `//FGI S//REL TO USA, GBR`
///   An empty `countries` list indicates source-concealed FGI.
///
/// Countries are space-delimited in the source marking.
///
/// # Disambiguation from sibling axes
///
/// - [`FgiMarker`] is a **dissem-axis** marker for commingled US+FGI
///   banner forms (`SECRET//FGI GBR DEU//...`), separate from the
///   classification axis modeled here. The two can coexist.
/// - [`JointClassification`] models US-inclusive co-ownership where
///   the US is itself one of the producers. `FgiClassification` is the
///   non-US classification axis and does not include the US.
///
/// # Banner aggregation
///
/// If a document contains **any** source-concealed FGI portions alongside
/// source-acknowledged FGI portions, the banner must use `FGI` without
/// country codes — revealing the country list would compromise the
/// concealed source. This rule is enforced at the `PageContext` level
/// during banner validation.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct FgiClassification {
    /// Originating countries (space-delimited in source).
    /// Empty for source-concealed FGI (`//FGI S//...`).
    pub countries: Box<[CountryCode]>,
    /// Classification level (includes RESTRICTED).
    pub level: Classification,
}

// ---------------------------------------------------------------------------
// NATO classification
// ---------------------------------------------------------------------------

/// NATO classification ladder.
///
/// NATO uses a separate classification system governed by treaty.
/// Not everyone with a US clearance is cleared for NATO; many US systems
/// are not approved for NATO information.
///
/// # Canonical structural model (PR 9c.1 T134)
///
/// Per CAPCO-2016 §G.2 p40 (Table 5: ARH by Registered Marking),
/// ATOMAL / BOHEMIA / BALK are **registered NATO control markings,
/// not NATO classifications** — each has its own ARH row with
/// `Requires {marking} read-in`. The §H.7 p122 + §H.7 p127 worked
/// examples place them in their proper category positions:
///
/// - **ATOMAL** is an AEA-axis marking shared with NATO+UK under
///   §123/§144 sharing agreements (Atomic Energy Act). It travels
///   alongside RD/FRD/TFNI in the AEA block, carried by
///   [`AeaMarking::Atomal`]. Canonical portion: `(//CTS//ATOMAL)` or
///   `(//NS//ATOMAL)`, not the legacy `CTSA` / `NSAT` portion-suffix.
/// - **BOHEMIA** and **BALK** are NATO Special Access Programs in
///   the SCI category position, carried by
///   [`SciControlSystem::NatoSap`]. They render standalone with no
///   `SAR-` prefix. Canonical portion: `(//CTS//BOHEMIA)` or
///   `(//CTS//BALK)`, not the legacy `CTS-B` / `CTS-BALK`
///   portion-suffix.
///
/// Pre-PR-9c.1 carried five fused variants — `NatoConfidentialAtomal`,
/// `NatoSecretAtomal`, `CosmicTopSecretAtomal`,
/// `CosmicTopSecretBohemia`, `CosmicTopSecretBalk` — which conflated
/// classification with AEA/SCI semantics on a single axis. The
/// parser ([`crate::parser::parse_nato_classification`] in marque-core)
/// canonicalizes legacy text at parse time; the E066 autofix rule
/// rewrites the source text to the canonical multi-block form.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum NatoClassification {
    NatoUnclassified, // NU
    NatoRestricted,   // NR
    NatoConfidential, // NC
    NatoSecret,       // NS
    CosmicTopSecret,  // CTS
}

impl NatoClassification {
    /// Banner form (full words, as used in banner marking lines).
    pub fn banner_str(self) -> &'static str {
        match self {
            Self::NatoUnclassified => "NATO UNCLASSIFIED",
            Self::NatoRestricted => "NATO RESTRICTED",
            Self::NatoConfidential => "NATO CONFIDENTIAL",
            Self::NatoSecret => "NATO SECRET",
            Self::CosmicTopSecret => "COSMIC TOP SECRET",
        }
    }

    /// Portion form (primary abbreviation from the CAPCO Register).
    pub fn portion_str(self) -> &'static str {
        match self {
            Self::NatoUnclassified => "NU",
            Self::NatoRestricted => "NR",
            Self::NatoConfidential => "NC",
            Self::NatoSecret => "NS",
            Self::CosmicTopSecret => "CTS",
        }
    }

    /// The base classification level, for ordering comparisons.
    ///
    /// PR 9c.1 T134: `base_level` collapses to a trivial mapping
    /// post-variant-retirement (each variant is its own base level),
    /// but the indirection stays for API stability and as a hook
    /// for any future sub-level distinctions.
    pub fn base_level(self) -> NatoLevel {
        match self {
            Self::NatoUnclassified => NatoLevel::NatoUnclassified,
            Self::NatoRestricted => NatoLevel::NatoRestricted,
            Self::NatoConfidential => NatoLevel::NatoConfidential,
            Self::NatoSecret => NatoLevel::NatoSecret,
            Self::CosmicTopSecret => NatoLevel::CosmicTopSecret,
        }
    }

    /// Map the NATO level to the equivalent US classification for conflict
    /// resolution (US wins at the greater of the two).
    pub fn us_equivalent(self) -> Classification {
        match self.base_level() {
            NatoLevel::NatoUnclassified => Classification::Unclassified,
            NatoLevel::NatoRestricted => Classification::Restricted,
            NatoLevel::NatoConfidential => Classification::Confidential,
            NatoLevel::NatoSecret => Classification::Secret,
            NatoLevel::CosmicTopSecret => Classification::TopSecret,
        }
    }
}

/// NATO classification level without SAP, for ordering comparisons.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum NatoLevel {
    NatoUnclassified,
    NatoRestricted,
    NatoConfidential,
    NatoSecret,
    CosmicTopSecret,
}

// ---------------------------------------------------------------------------
// JOINT classification
// ---------------------------------------------------------------------------

/// JOINT classification: US is co-owner with other nations.
///
/// `//JOINT S USA GBR//REL TO USA, GBR`
///
/// Country list is space-delimited (NOT comma-delimited like REL TO).
/// Must include USA. All JOINT participants must also appear in REL TO.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct JointClassification {
    /// Classification level (US ladder, includes RESTRICTED).
    pub level: Classification,
    /// Co-owning countries (space-delimited in source). Must include USA.
    pub countries: Box<[CountryCode]>,
}

// ---------------------------------------------------------------------------
// Atomic Energy Act markings
// ---------------------------------------------------------------------------

/// Atomic Energy Act information markings (CAPCO-2016 §H.6 pp 103–121).
///
/// AEA markings appear as a single `//`-delimited block in the marking string,
/// using hyphen separators for compound forms:
/// - `SECRET//RD//NOFORN` — RD alone
/// - `SECRET//RD-CNWDI//NOFORN` — RD with CNWDI modifier
/// - `SECRET//RD-SIGMA 20//NOFORN` — RD with SIGMA compartment
/// - `SECRET//RD-SIGMA 18 20//NOFORN` — RD with multiple SIGMAs
/// - `SECRET//FRD//NOFORN` — FRD alone
/// - `SECRET//FRD-SIGMA 14//NOFORN` — FRD with SIGMA
///
/// Standalone (non-compound) markings:
/// - `UNCLASSIFIED//DOD UCNI` / `(U//DCNI)`
/// - `UNCLASSIFIED//DOE UCNI` / `(U//UCNI)`
/// - `SECRET//TFNI//NOFORN` / `(S//TFNI//NF)`
///
/// # Key rules (CAPCO-2016)
///
/// - RD and FRD always require NOFORN unless a sharing agreement exists
///   (default severity: Error, configurable to Warn via `.marque.toml`)
/// - CNWDI may only be used with TS or S RD (not standalone, not with FRD)
/// - SIGMA 14, 15, 18, 20 may only be used with TS or S RD or FRD
/// - RD takes precedence over FRD and TFNI in both banners and portions
/// - SIGMA numbers must be in numerical order, space-separated
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
#[non_exhaustive]
pub enum AeaMarking {
    /// Compound RD block: `RD`, `RD-CNWDI`, `RD-SIGMA 20`, `RD-CNWDI-SIGMA 18 20`
    Rd(RdBlock),
    /// Compound FRD block: `FRD`, `FRD-SIGMA 14`
    Frd(FrdBlock),
    /// DOD UCNI / DCNI — standalone, unclassified only
    DodUcni,
    /// DOE UCNI / UCNI — standalone, unclassified only
    DoeUcni,
    /// TFNI — standalone
    Tfni,
    /// ATOMAL — NATO Atomic Energy Act information shared with the US
    /// and UK under bilateral §123 / §144 agreements (Atomic Energy
    /// Act §141–§144). Travels in the AEA axis alongside RD/FRD/TFNI
    /// (CAPCO-2016 §H.7 p122 worked example:
    /// `SECRET//RD/ATOMAL//FGI NATO//NOFORN`). Rendered as `ATOMAL`
    /// in both banner and portion forms.
    ///
    /// `AtomalBlock` is currently empty — ATOMAL has no registered
    /// sub-markings in CAPCO-2016 §H.7. The block carrier mirrors
    /// [`RdBlock`] / [`FrdBlock`] so a future CAPCO publication that
    /// grammar-extends ATOMAL with sub-markings remains a planned
    /// migration rather than a breaking-shape change.
    Atomal(AtomalBlock),
}

/// Restricted Data block with optional modifiers.
///
/// Rendered as `RD`, `RD-CNWDI`, `RD-SIGMA 20`, or `RD-CNWDI-SIGMA 18 20`.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct RdBlock {
    /// Whether CNWDI is present. Only valid with TS or S classification.
    pub cnwdi: bool,
    /// SIGMA compartment numbers (14, 15, 18, 20). Must be in numerical order.
    /// Empty if no SIGMA designation.
    pub sigma: Box<[u8]>,
}

impl Default for RdBlock {
    fn default() -> Self {
        Self {
            cnwdi: false,
            sigma: Box::new([]),
        }
    }
}

/// Formerly Restricted Data block with optional SIGMA modifier.
///
/// Rendered as `FRD` or `FRD-SIGMA 14`.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct FrdBlock {
    /// SIGMA compartment numbers. Must be in numerical order.
    /// Empty if no SIGMA designation.
    pub sigma: Box<[u8]>,
}

impl Default for FrdBlock {
    fn default() -> Self {
        Self {
            sigma: Box::new([]),
        }
    }
}

/// ATOMAL block.
///
/// Currently empty: CAPCO-2016 §G.2 p40 + §H.7 p122 register
/// ATOMAL as a standalone control marking with no enumerated
/// sub-markings. The carrier struct mirrors the [`RdBlock`] /
/// [`FrdBlock`] shape so that adding sub-markings in a future CAPCO
/// publication remains a planned, intentional grammar extension
/// rather than a structural-shape change at the variant level.
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq, Hash)]
pub struct AtomalBlock;

impl AeaMarking {
    /// Banner-line form.
    pub fn banner_str(&self) -> String {
        match self {
            Self::Rd(rd) => {
                let mut s = "RD".to_owned();
                if rd.cnwdi {
                    s.push_str("-CNWDI");
                }
                if !rd.sigma.is_empty() {
                    s.push_str("-SIGMA ");
                    let nums: Vec<String> = rd.sigma.iter().map(|n| n.to_string()).collect();
                    s.push_str(&nums.join(" "));
                }
                s
            }
            Self::Frd(frd) => {
                let mut s = "FRD".to_owned();
                if !frd.sigma.is_empty() {
                    s.push_str("-SIGMA ");
                    let nums: Vec<String> = frd.sigma.iter().map(|n| n.to_string()).collect();
                    s.push_str(&nums.join(" "));
                }
                s
            }
            Self::DodUcni => "DOD UCNI".to_owned(),
            Self::DoeUcni => "DOE UCNI".to_owned(),
            Self::Tfni => "TFNI".to_owned(),
            Self::Atomal(_) => "ATOMAL".to_owned(),
        }
    }

    /// Portion mark form.
    pub fn portion_str(&self) -> String {
        match self {
            Self::Rd(rd) => {
                let mut s = "RD".to_owned();
                if rd.cnwdi {
                    s.push_str("-CNWDI");
                }
                if !rd.sigma.is_empty() {
                    s.push_str("-SG ");
                    let nums: Vec<String> = rd.sigma.iter().map(|n| n.to_string()).collect();
                    s.push_str(&nums.join(" "));
                }
                s
            }
            Self::Frd(frd) => {
                let mut s = "FRD".to_owned();
                if !frd.sigma.is_empty() {
                    s.push_str("-SG ");
                    let nums: Vec<String> = frd.sigma.iter().map(|n| n.to_string()).collect();
                    s.push_str(&nums.join(" "));
                }
                s
            }
            Self::DodUcni => "DCNI".to_owned(),
            Self::DoeUcni => "UCNI".to_owned(),
            Self::Tfni => "TFNI".to_owned(),
            Self::Atomal(_) => "ATOMAL".to_owned(),
        }
    }

    /// Parse a `//`-delimited AEA block from either banner or portion form.
    ///
    /// Handles compound tokens: `RD`, `RD-CNWDI`, `RD-SIGMA 20`,
    /// `RD-CNWDI-SIGMA 18 20`, `FRD`, `FRD-SIGMA 14`, etc.
    pub fn parse(s: &str) -> Option<Self> {
        // Standalone non-compound markings.
        match s {
            "DOD UCNI" | "DCNI" => return Some(Self::DodUcni),
            "DOE UCNI" | "UCNI" => return Some(Self::DoeUcni),
            "TFNI" | "TRANSCLASSIFIED FOREIGN NUCLEAR INFORMATION" => return Some(Self::Tfni),
            // ATOMAL — NATO §123/§144 sharing per CAPCO-2016 §H.7 p122.
            // Banner and portion forms are identical (`ATOMAL`).
            "ATOMAL" => return Some(Self::Atomal(AtomalBlock)),
            _ => {}
        }

        // RD compound block: RD, RD-CNWDI, RD-SIGMA ##, RD-CNWDI-SIGMA ##,
        // RESTRICTED DATA, RESTRICTED DATA-CNWDI, etc.
        if s == "RD" || s == "RESTRICTED DATA" {
            return Some(Self::Rd(RdBlock::default()));
        }
        if let Some(rest) = s
            .strip_prefix("RD-")
            .or_else(|| s.strip_prefix("RESTRICTED DATA-"))
        {
            return Self::parse_rd_modifiers(rest);
        }

        // FRD compound block: FRD, FRD-SIGMA ##,
        // FORMERLY RESTRICTED DATA, etc.
        if s == "FRD" || s == "FORMERLY RESTRICTED DATA" {
            return Some(Self::Frd(FrdBlock::default()));
        }
        if let Some(rest) = s
            .strip_prefix("FRD-")
            .or_else(|| s.strip_prefix("FORMERLY RESTRICTED DATA-"))
        {
            return Self::parse_frd_modifiers(rest);
        }

        None
    }

    /// Parse RD modifiers after the `RD-` prefix.
    /// Handles: `CNWDI`, `SIGMA ##`, `CNWDI-SIGMA ##`, `SG ##`, `CNWDI-SG ##`.
    fn parse_rd_modifiers(s: &str) -> Option<Self> {
        let mut cnwdi = false;
        let mut rest = s;

        // Check for CNWDI prefix.
        if let Some(after) = rest.strip_prefix("CNWDI") {
            cnwdi = true;
            rest = after.strip_prefix('-').unwrap_or(after);
        } else if rest == "N" {
            // DoD shorthand: RD-N means RD-CNWDI (per CAPCO-2016 §6)
            return Some(Self::Rd(RdBlock {
                cnwdi: true,
                sigma: Box::new([]),
            }));
        }

        // Check for SIGMA/SG.
        let sigma = parse_sigma_numbers(rest);

        if rest.is_empty() || !sigma.is_empty() {
            Some(Self::Rd(RdBlock {
                cnwdi,
                sigma: sigma.into(),
            }))
        } else {
            None
        }
    }

    /// Parse FRD modifiers after the `FRD-` prefix.
    /// Handles: `SIGMA ##`, `SG ##`.
    fn parse_frd_modifiers(s: &str) -> Option<Self> {
        let sigma = parse_sigma_numbers(s);
        if !sigma.is_empty() {
            Some(Self::Frd(FrdBlock {
                sigma: sigma.into(),
            }))
        } else {
            None
        }
    }
}

/// Parse SIGMA/SG numbers from a string like `SIGMA 18 20` or `SG 14`.
fn parse_sigma_numbers(s: &str) -> Vec<u8> {
    let rest = s
        .strip_prefix("SIGMA ")
        .or_else(|| s.strip_prefix("SG "))
        .unwrap_or("");
    if rest.is_empty() {
        return vec![];
    }
    rest.split_whitespace()
        .filter_map(|n| n.parse::<u8>().ok())
        .collect()
}

impl std::fmt::Display for AeaMarking {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.write_str(&self.portion_str())
    }
}

// ---------------------------------------------------------------------------
// FGI marker (in US-classified markings)
// ---------------------------------------------------------------------------

/// FGI marker in a US-classified marking: `FGI` (source-concealed) or
/// `FGI [LIST]` (source-acknowledged).
///
/// Appears in the FGI block (after SAR, before dissem controls) when a
/// US-classified document references foreign government information.
///
/// This is NOT the same as [`FgiClassification`] — that represents a
/// marking where the classification itself IS foreign. This marker says
/// "this US-classified marking contains foreign government information."
///
/// # Authoritative source
///
/// CAPCO-2016 §H.7 p122 defines two banner forms:
///
/// | Variant | Banner | Portion |
/// |---|---|---|
/// | Source-acknowledged | `FOREIGN GOVERNMENT INFORMATION [LIST]` (abbr `FGI [LIST]`) | with country trigraphs |
/// | Source-concealed    | `FOREIGN GOVERNMENT INFORMATION` (abbr `FGI`)              | without country list |
///
/// Concealment is used when revealing the country list would compromise
/// the foreign source. If a page mixes concealed + acknowledged portions,
/// the banner must use the concealed form (bare `FGI`).
///
/// # Why an enum, not a struct with `Box<[CountryCode]>`
///
/// The previous shape `FgiMarker { countries: Box<[CountryCode]> }`
/// made `countries: []` ambiguous between two meanings:
///
///   1. Lawful source-concealed FGI (the `FGI` banner form).
///   2. A parser failure that silently dropped a country list — the
///      classic open-vocabulary corruption case (issue #280).
///
/// FR-017 / CHK028 retire that collision by making the discriminant
/// explicit. `Acknowledged` is constructed only via [`acknowledged`],
/// which rejects an empty country list, so the corrupt shape is
/// type-system-unrepresentable.
///
/// [`acknowledged`]: FgiMarker::acknowledged
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum FgiMarker {
    /// Source-concealed FGI per CAPCO-2016 §H.7 p122.
    ///
    /// Banner: `FOREIGN GOVERNMENT INFORMATION` (abbr `FGI`) with no
    /// country list. Used when revealing the country list would
    /// compromise the foreign source.
    SourceConcealed,

    /// Source-acknowledged FGI per CAPCO-2016 §H.7 p123.
    ///
    /// Banner: `FOREIGN GOVERNMENT INFORMATION [LIST]` (abbr
    /// `FGI [LIST]`). The country list is non-empty by construction —
    /// see [`FgiMarker::acknowledged`] for the public constructor that
    /// enforces the invariant.
    ///
    /// Marked `#[non_exhaustive]` so external crates **cannot**
    /// construct this variant via struct-literal syntax. This is
    /// load-bearing for FR-017 / CHK028: it forces external callers
    /// through [`FgiMarker::acknowledged`], which rejects the empty
    /// country list. Pattern matching from outside the crate still
    /// works with the `..` rest pattern:
    /// `FgiMarker::Acknowledged { countries, .. }`. Internal
    /// (in-crate) construction is unrestricted, but only the
    /// `acknowledged` constructor reaches the variant in this crate's
    /// codepaths — see callsites for the audit.
    #[non_exhaustive]
    Acknowledged {
        /// One or more country trigraphs/tetragraphs. Non-empty by
        /// construction (enforced by [`FgiMarker::acknowledged`]).
        ///
        /// `SmallVec<[CountryCode; 4]>` keeps the typical FGI list
        /// (≤4 codes) inline — no heap allocation on the parsing
        /// hot path (Constitution Principle II).
        countries: SmallVec<[CountryCode; 4]>,
    },
}

impl FgiMarker {
    /// Construct an acknowledged FGI marker from a non-empty list of
    /// country codes. Returns `None` if the list is empty — at that
    /// point the caller has either parser-failure data (return `None`
    /// to the caller and let it surface as a diagnostic) or the source
    /// is genuinely concealed (use [`FgiMarker::SourceConcealed`]
    /// directly).
    ///
    /// Authority: CAPCO-2016 §H.7 p122 (the `FGI [LIST]` banner form
    /// requires a non-empty `[LIST]`).
    pub fn acknowledged<I>(countries: I) -> Option<Self>
    where
        I: IntoIterator<Item = CountryCode>,
    {
        let countries: SmallVec<[CountryCode; 4]> = countries.into_iter().collect();
        if countries.is_empty() {
            None
        } else {
            Some(Self::Acknowledged { countries })
        }
    }

    /// Country trigraphs for this marker.
    ///
    /// - `SourceConcealed` → empty slice (no countries by definition;
    ///   distinguishable from a parse failure because the variant
    ///   itself is the disambiguator).
    /// - `Acknowledged { countries }` → `&countries[..]`, guaranteed
    ///   non-empty by the [`FgiMarker::acknowledged`] constructor.
    pub fn countries(&self) -> &[CountryCode] {
        match self {
            Self::SourceConcealed => &[],
            Self::Acknowledged { countries } => countries.as_slice(),
        }
    }

    /// `true` iff this is a source-concealed marker (the bare `FGI`
    /// banner form, CAPCO-2016 §H.7 p122).
    pub fn is_concealed(&self) -> bool {
        matches!(self, Self::SourceConcealed)
    }
}

// ===========================================================================
// Non-IC dissemination controls
// ===========================================================================

/// Non-Intelligence Community dissemination control markings (CAPCO-2016 §H.9 pp 169–191).
///
/// These operate under a separate authority framework from IC dissem controls.
/// In classified documents, most non-IC dissem controls appear **only in portion
/// markings** — they are stripped from banners. However, some controls propagate
/// to classified banners: LIMDIS (NGA Title 10), LES, LES-NF, and SSI. See
/// [`NonIcDissem::propagates_to_classified_banner`] for the authoritative list.
/// When the page is **unclassified**, all non-IC dissem controls propagate to
/// the banner.
///
/// LES-NF and SBU-NF carry NOFORN treatment even when stripped from the banner.
///
/// # CUI note
///
/// CUI (Controlled Unclassified Information) is recognized but not validated.
/// Full CUI rule support is planned for a dedicated crate. The IC equivalent
/// (FOUO) remains in active use in the `DissemControl` enum.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
#[non_exhaustive]
pub enum NonIcDissem {
    /// LIMITED DISTRIBUTION / LIMDIS / DS
    Limdis,
    /// EXCLUSIVE DISTRIBUTION / EXDIS / XD
    Exdis,
    /// NO DISTRIBUTION / NODIS / ND
    Nodis,
    /// SENSITIVE BUT UNCLASSIFIED / SBU / SBU
    Sbu,
    /// SENSITIVE BUT UNCLASSIFIED NOFORN / SBU NOFORN / SBU-NF
    /// Carries NOFORN treatment even when stripped from banner.
    SbuNf,
    /// LAW ENFORCEMENT SENSITIVE / LES / LES
    Les,
    /// LAW ENFORCEMENT SENSITIVE NOFORN / LES NOFORN / LES-NF
    /// Carries NOFORN treatment even when stripped from banner.
    LesNf,
    /// SENSITIVE SECURITY INFORMATION / SSI / SSI
    Ssi,
    /// NAVAL NUCLEAR PROPULSION INFORMATION / NNPI / NNPI
    ///
    /// Registered as a non-IC dissemination control in ODNI's
    /// `CVEnumISMNonIC.xml` (value `NNPI`, description
    /// `NAVAL NUCLEAR PROPULSION INFORMATION`). CAPCO-2016 §G.1
    /// Table 4 (Register of Authorized Markings) and §H.9 (Non-IC
    /// Dissemination Control Markings) do not enumerate NNPI,
    /// because the marking is governed by separate statutory
    /// authority (10 USC 7314 / 50 USC 2511; DOE / Naval Nuclear
    /// Propulsion Program) rather than IC marking policy. Per
    /// Constitution VIII, an ODNI-registered token whose authority
    /// lives outside CAPCO is admissible via the ODNI schema
    /// citation when the normative CAPCO sections cited above are
    /// silent on the marking itself.
    ///
    /// NNPI is a subject-matter marking — it identifies the
    /// information's content domain (naval nuclear propulsion plant
    /// reactor safety and radioactivity controls) rather than an
    /// access-control overlay. NNPI is "DO propagate" for
    /// `propagates_to_classified_banner` because NNPI can appear in
    /// either classified or unclassified contexts (unlike the
    /// LIMDIS / SBU / SBU-NF cluster, which is explicitly
    /// unclassified-only per §H.9 p178). When NNPI appears in any
    /// portion of a classified document, the banner must surface it
    /// — the marking identifies the information itself, not an
    /// optional access restriction. As with all non-IC dissem
    /// controls, classified+NNPI absent an explicit FD&R decision
    /// is implicitly NOFORN per the §B.3 p20 Note caveated-default
    /// (the IC cannot presume releasability or RELIDO-suitability of
    /// information governed by policy regimes outside IC marking
    /// authority); the closure-rule wiring lives in
    /// `crates/capco/src/scheme/closure.rs` under the row whose
    /// `name` field is `"capco/noforn-if-non-ic-controls"`.
    Nnpi,
}

impl NonIcDissem {
    /// Banner-line abbreviation form.
    pub fn banner_str(self) -> &'static str {
        match self {
            Self::Limdis => "LIMDIS",
            Self::Exdis => "EXDIS",
            Self::Nodis => "NODIS",
            Self::Sbu => "SBU",
            Self::SbuNf => "SBU NOFORN",
            Self::Les => "LES",
            Self::LesNf => "LES NOFORN",
            Self::Ssi => "SSI",
            Self::Nnpi => "NNPI",
        }
    }

    /// Portion mark abbreviation.
    pub fn portion_str(self) -> &'static str {
        match self {
            Self::Limdis => "DS",
            Self::Exdis => "XD",
            Self::Nodis => "ND",
            Self::Sbu => "SBU",
            Self::SbuNf => "SBU-NF",
            Self::Les => "LES",
            Self::LesNf => "LES-NF",
            Self::Ssi => "SSI",
            Self::Nnpi => "NNPI",
        }
    }

    /// Parse from either banner or portion form.
    pub fn parse(s: &str) -> Option<Self> {
        match s {
            "LIMDIS" | "DS" => Some(Self::Limdis),
            "EXDIS" | "XD" => Some(Self::Exdis),
            "NODIS" | "ND" => Some(Self::Nodis),
            "SBU" => Some(Self::Sbu),
            "SBU NOFORN" | "SBU-NF" => Some(Self::SbuNf),
            "LES" => Some(Self::Les),
            "LES NOFORN" | "LES-NF" => Some(Self::LesNf),
            "SSI" => Some(Self::Ssi),
            // Banner and portion forms collide on `NNPI` (same
            // single-token form for both, per the `MARKING_FORMS`
            // row at `crates/ism/src/marking_forms.rs`). The long
            // form `NAVAL NUCLEAR PROPULSION INFORMATION` resolves
            // to `NNPI` via `parse_non_ic_full_form`'s
            // `title_to_portion` fallback, not here.
            "NNPI" => Some(Self::Nnpi),
            _ => None,
        }
    }

    /// Returns true if this control carries NOFORN treatment.
    pub fn carries_noforn(self) -> bool {
        matches!(self, Self::SbuNf | Self::LesNf)
    }

    /// Returns true if this control propagates to classified banners.
    ///
    /// Authoritative source: `crates/capco/docs/CAPCO-2016.md` §H.9
    /// "Precedence Rules for Banner Line Guidance" for each marking.
    /// The per-marking rows below cite the specific line of the vendored
    /// manual.
    ///
    /// | Marking  | Propagates | Source (CAPCO-2016 §H.9)                                                                                            |
    /// |----------|------------|----------------------------------------------------------------------------------------------------------------------|
    /// | LIMDIS   | no         | §H.9 p170: "When a document contains LIMDIS and classified portions, LIMDIS is not used in the banner line."         |
    /// | EXDIS    | yes        | §H.9 p172: "If EXDIS is contained in any portion … EXDIS must appear in the banner line." Example banner: `SECRET//NOFORN//EXDIS` |
    /// | NODIS    | yes        | §H.9 p174: "If NODIS is contained in any portion of a document, it must appear in the banner line." Example banner: `SECRET//NOFORN//NODIS` |
    /// | SBU      | no         | §H.9 p176: "When a document contains SBU and classified portions, SBU is not used in the banner line."               |
    /// | SBU-NF   | no (†)     | §H.9 p178: SBU NOFORN "Applicable only to unclassified information." (The §H.9 notional example on p179 shows a `SECRET//NOFORN` banner with a `(U//SBU-NF)` portion — SBU-NF absent from banner.) |
    /// | LES      | yes        | §H.9 p181: "The LES marking always appears in the banner line if contained in any portion, regardless of classification level." |
    /// | LES-NF   | yes (*)    | §H.9 p185: "The LES marking always appears in the banner line if LES information (either LES or LES NOFORN) is contained in the document, regardless of the document's classification level." |
    /// | SSI      | yes        | §H.9 p189: "If the SSI marking is contained in any portion of a document it must appear in the banner line, regardless of the document's overall classification level." |
    /// | NNPI     | yes (‡)    | Not in §H.9. ODNI `CVEnumISMNonIC.xml` registers NNPI as a non-IC dissem control; 10 USC 7314 / 50 USC 2511 (Naval Nuclear Propulsion Program) governs the marking itself. NNPI can appear in either classified or unclassified contexts (unlike the LIMDIS / SBU / SBU-NF cluster, which §H.9 p170 / p176 / p178 restrict to unclassified-only). When NNPI appears in any portion of a classified document, the banner must surface it — the marking identifies the information's content domain (naval nuclear propulsion plant reactor safety + radioactivity controls), not an optional access overlay. |
    ///
    /// (*) LES-NF carries a §H.9 canonicalization that is **not modeled
    ///     here**: in classified docs, `LES NOFORN` → `LES` at the banner
    ///     with NOFORN split into the dissem block (§H.9 p185: "the 'LES'
    ///     marking is used in the banner line and the NOFORN marking is
    ///     applied as a Dissemination Control Marking. For example:
    ///     `SECRET//NOFORN//LES`."). The split itself is handled by
    ///     [`crate::PageContext::expected_non_ic_dissem`]; this predicate
    ///     only answers the binary "does the marking appear in the
    ///     banner at all?" question, which is what W003 consumes.
    ///     Treating `SECRET//LES NOFORN` as non-canonical (so that the
    ///     canonicalization becomes fixable) is a separate page-rewrite
    ///     concern, not a W003 concern.
    ///
    /// (‡) NNPI does not have a §H.9 row at all — its authority lives
    ///     outside CAPCO's IC-marking scope (10 USC 7314 / 50 USC
    ///     §2511). Per Constitution VIII, citing the ODNI schema
    ///     when the normative CAPCO sections cited above are silent
    ///     on the marking itself is admissible.
    ///
    /// (†) "Does not propagate" for SBU-NF refers to the **SBU** half of
    ///     the marking — the literal `SBU NOFORN` banner form is
    ///     non-canonical in a classified document per §H.9 p178
    ///     ("applicable only to unclassified information"). The **NOFORN
    ///     half does propagate** via
    ///     [`crate::PageContext::expected_non_ic_dissem`], which splits a
    ///     portion-level `SBU-NF` into `SBU + NF-flag` and emits the
    ///     resulting NOFORN into the classified banner's dissem block.
    ///     So a document with a `(U//SBU-NF)` portion rolls up to a
    ///     `SECRET//NOFORN` banner (NOFORN present, SBU dropped), not
    ///     `SECRET//SBU NOFORN`. W003 therefore fires on the literal
    ///     `SECRET//SBU NOFORN` banner input because that surface form
    ///     is the non-canonical one, not because NOFORN is disallowed.
    pub fn propagates_to_classified_banner(self) -> bool {
        match self {
            // Do NOT propagate — banner-absent in classified documents.
            Self::Limdis | Self::Sbu | Self::SbuNf => false,
            // DO propagate — "must appear in the banner line" per §H.9.
            //
            // NNPI propagates: it is a subject-matter identification
            // marking (10 USC 7314 / 50 USC 2511 Naval Nuclear
            // Propulsion Program), not an optional access overlay,
            // so any portion carrying NNPI requires the banner to
            // surface it as well. ODNI's `CVEnumISMNonIC.xml`
            // registers it alongside the §H.9 propagating set; the
            // governing statutes treat banner visibility as
            // mandatory for any document containing NNPI content.
            Self::Exdis | Self::Nodis | Self::Les | Self::LesNf | Self::Ssi | Self::Nnpi => true,
        }
    }

    /// All valid values.
    pub const ALL: &[NonIcDissem] = &[
        Self::Limdis,
        Self::Exdis,
        Self::Nodis,
        Self::Sbu,
        Self::SbuNf,
        Self::Les,
        Self::LesNf,
        Self::Ssi,
        Self::Nnpi,
    ];
}

impl std::fmt::Display for NonIcDissem {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.write_str(self.portion_str())
    }
}

// ===========================================================================
// CountryCode
// ===========================================================================

/// Maximum byte length of a CAPCO country code.
///
/// The longest entry in `CVEnumISMCATRelTo.xsd` is `AUSTRALIA_GROUP`
/// (15 bytes); 16 leaves one byte of headroom for any future
/// addition without forcing a struct-layout change.
const COUNTRY_CODE_CAPACITY: usize = 16;

/// A CAPCO country / country-group code, 2–16 ASCII bytes.
///
/// Covers every entry in the CVE country code list:
/// - 1× 2-char (`EU`)
/// - 280× 3-char trigraphs (`USA`, `GBR`, `AUS`, …)
/// - 58× 4-char tetragraphs / country-group codes (`FVEY`, `ACGU`,
///   `NATO`, `RSMA`, …)
/// - 1× 15-char (`AUSTRALIA_GROUP`)
///
/// The inner bytes are private; construction goes through
/// [`CountryCode::try_new`] which enforces the CAPCO byte-set invariant
/// (ASCII uppercase letters, ASCII digits, underscore — covers `AX2`,
/// `AX3`, `AUSTRALIA_GROUP`, and the standard alpha trigraphs/
/// tetragraphs) so that [`CountryCode::as_str`] can return a `&str`
/// infallibly without panicking at runtime.
///
/// `Copy` is preserved so the type composes in iterator chains and
/// `BTreeSet`-based intersection without manual `.clone()` calls.
/// The fixed-array form keeps each `CountryCode` entry inline in
/// `CanonicalAttrs::rel_to` (`Box<[CountryCode]>`) on the parsing
/// hot path — no per-code heap allocation.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct CountryCode {
    /// Code bytes, zero-padded after `len`. Derived `Ord` compares
    /// lexicographically on the padded bytes; zero-padding makes
    /// shorter codes with a shared prefix sort first, matching `&str`
    /// ordering on ASCII.
    bytes: [u8; COUNTRY_CODE_CAPACITY],
    /// Active byte count, `2..=COUNTRY_CODE_CAPACITY`.
    len: u8,
}

impl CountryCode {
    /// The always-valid `USA` country code constant.
    ///
    /// Constructed via [`CountryCode::try_new`] in `const` context.
    /// The `panic!` arm is statically unreachable for `b"USA"`
    /// (3 bytes, all ASCII uppercase) and exists only because
    /// `const fn` does not yet permit unwrapping an `Option` —
    /// `match` is the workaround.
    pub const USA: Self = match Self::try_new(b"USA") {
        Some(c) => c,
        None => panic!("CountryCode::USA literal must satisfy try_new invariants"),
    };

    // The remaining Five Eyes constituent codes (AUS / CAN / GBR / NZL) —
    // used by E064 FVEY-expansion in `marque-capco`. The NATO tetragraph
    // is forward-investment for the NATO classification closure cone
    // deferred to #508 (PR 4b-D); same const-construction shape so the
    // future closure row can reference `CountryCode::NATO` directly.

    /// The always-valid `AUS` country code constant.
    ///
    /// Constructed via [`CountryCode::try_new`] in `const` context.
    /// The `panic!` arm is statically unreachable for `b"AUS"`
    /// (3 bytes, all ASCII uppercase) and exists only because
    /// `const fn` does not yet permit unwrapping an `Option` —
    /// `match` is the workaround.
    pub const AUS: Self = match Self::try_new(b"AUS") {
        Some(c) => c,
        None => panic!("CountryCode::AUS literal must satisfy try_new invariants"),
    };

    /// The always-valid `CAN` country code constant.
    ///
    /// Constructed via [`CountryCode::try_new`] in `const` context.
    /// The `panic!` arm is statically unreachable for `b"CAN"`
    /// (3 bytes, all ASCII uppercase) and exists only because
    /// `const fn` does not yet permit unwrapping an `Option` —
    /// `match` is the workaround.
    pub const CAN: Self = match Self::try_new(b"CAN") {
        Some(c) => c,
        None => panic!("CountryCode::CAN literal must satisfy try_new invariants"),
    };

    /// The always-valid `GBR` country code constant.
    ///
    /// Constructed via [`CountryCode::try_new`] in `const` context.
    /// The `panic!` arm is statically unreachable for `b"GBR"`
    /// (3 bytes, all ASCII uppercase) and exists only because
    /// `const fn` does not yet permit unwrapping an `Option` —
    /// `match` is the workaround.
    pub const GBR: Self = match Self::try_new(b"GBR") {
        Some(c) => c,
        None => panic!("CountryCode::GBR literal must satisfy try_new invariants"),
    };

    /// The always-valid `NZL` country code constant.
    ///
    /// Constructed via [`CountryCode::try_new`] in `const` context.
    /// The `panic!` arm is statically unreachable for `b"NZL"`
    /// (3 bytes, all ASCII uppercase) and exists only because
    /// `const fn` does not yet permit unwrapping an `Option` —
    /// `match` is the workaround.
    pub const NZL: Self = match Self::try_new(b"NZL") {
        Some(c) => c,
        None => panic!("CountryCode::NZL literal must satisfy try_new invariants"),
    };

    /// The always-valid `NATO` tetragraph constant.
    ///
    /// Constructed via [`CountryCode::try_new`] in `const` context.
    /// The `panic!` arm is statically unreachable for `b"NATO"`
    /// (4 bytes, all ASCII uppercase) and exists only because
    /// `const fn` does not yet permit unwrapping an `Option` —
    /// `match` is the workaround.
    ///
    /// Forward-investment for the deferred NATO classification
    /// closure row tracked in #508 (PR 4b-D). The closure cone,
    /// severity, suppressor set, and S007 interaction are open
    /// design decisions — see #508 for the calibration question.
    pub const NATO: Self = match Self::try_new(b"NATO") {
        Some(c) => c,
        None => panic!("CountryCode::NATO literal must satisfy try_new invariants"),
    };

    /// Returns `true` if `b` is in the CAPCO country-code byte set:
    /// ASCII uppercase letter, ASCII digit, or underscore. Digits cover
    /// `AX2`/`AX3`; underscore covers `AUSTRALIA_GROUP`.
    #[inline]
    const fn is_valid_byte(b: u8) -> bool {
        b.is_ascii_uppercase() || b.is_ascii_digit() || b == b'_'
    }

    /// Attempt to construct a country code from a byte slice.
    ///
    /// Returns `None` if `bytes`:
    /// - is shorter than 2 bytes (`EU` is the shortest CVE entry) or
    ///   longer than [`COUNTRY_CODE_CAPACITY`] bytes
    /// - contains any byte outside the CAPCO country-code byte set
    ///   (ASCII uppercase letter, ASCII digit, underscore)
    ///
    /// Membership in the CVE recognition set is a separate check —
    /// see [`crate::CapcoTokenSet::is_trigraph`] (the trait method
    /// covers any known country code, not only 3-char trigraphs).
    #[inline]
    pub const fn try_new(bytes: &[u8]) -> Option<Self> {
        let len = bytes.len();
        if len < 2 || len > COUNTRY_CODE_CAPACITY {
            return None;
        }
        let mut padded = [0u8; COUNTRY_CODE_CAPACITY];
        let mut i = 0;
        while i < len {
            if !Self::is_valid_byte(bytes[i]) {
                return None;
            }
            padded[i] = bytes[i];
            i += 1;
        }
        Some(Self {
            bytes: padded,
            len: len as u8,
        })
    }

    /// Return the country code as a string slice.
    ///
    /// Infallible because construction via [`CountryCode::try_new`]
    /// (or [`CountryCode::USA`]) guarantees every active byte is in the
    /// CAPCO byte set, which is a subset of ASCII / valid UTF-8.
    #[inline]
    pub fn as_str(&self) -> &str {
        // SAFETY: `CountryCode` can only be constructed via
        // `try_new` or constants (e.g. `CountryCode::USA`) that
        // route through `try_new` in const context. Both paths
        // require every active byte to be ASCII uppercase, ASCII
        // digit, or underscore. ASCII is a subset of valid UTF-8.
        #[allow(unsafe_code)]
        unsafe {
            std::str::from_utf8_unchecked(self.as_bytes())
        }
    }

    /// Active byte slice (excludes the zero padding).
    #[inline]
    pub fn as_bytes(&self) -> &[u8] {
        &self.bytes[..self.len as usize]
    }

    /// Number of active bytes, `2..=COUNTRY_CODE_CAPACITY`.
    #[inline]
    pub const fn len(&self) -> usize {
        self.len as usize
    }

    /// Always `false` — `CountryCode` invariants forbid empty codes.
    /// Provided for clippy-`len_without_is_empty` compliance.
    #[inline]
    pub const fn is_empty(&self) -> bool {
        false
    }

    /// Annex B trigraph admission predicate: exactly 3 ASCII uppercase
    /// letters `[A-Z]`. This is the shape building block for the
    /// trigraph-only half of the FGI / REL TO grammar; callers that
    /// need the *full* country-token grammar (trigraph **or**
    /// registered tetragraph) MUST go through
    /// [`CountryCode::admits_country_token`] instead — see Authority.
    ///
    /// Returns `true` iff `bytes` is a 3-byte slice whose every byte
    /// is in `b'A'..=b'Z'`. Stricter than [`CountryCode::try_new`],
    /// which also accepts ASCII digits (for `AX2` / `AX3`), the
    /// underscore (for `AUSTRALIA_GROUP`), and any 2-byte through
    /// 16-byte alphanumeric/underscore code.
    ///
    /// Authority: CAPCO-2016 §H.7 p122 (FGI Register Annex B trigraph
    /// country codes) + §A.6 p16 (alphabetic order of FGI list
    /// tokens). This predicate is the trigraph-only slice of the
    /// admission grammar; the FGI/REL TO list grammar at §H.7 p122
    /// and §H.8 p150 admits trigraphs *and* tetragraphs (e.g.,
    /// `SECRET//FGI GBR JPN NATO`, where `NATO` is a four-letter
    /// tetragraph from Register Annex A). Use
    /// [`CountryCode::admits_country_token`] for that full surface.
    ///
    /// # Examples
    ///
    /// ```
    /// use marque_ism::CountryCode;
    /// assert!(CountryCode::admits_fgi_trigraph(b"USA"));
    /// assert!(CountryCode::admits_fgi_trigraph(b"GBR"));
    /// // Rejected: too short.
    /// assert!(!CountryCode::admits_fgi_trigraph(b"US"));
    /// // Rejected: too long (tetragraph — admits via
    /// // `admits_country_token`, not this predicate).
    /// assert!(!CountryCode::admits_fgi_trigraph(b"NATO"));
    /// // Rejected: lowercase.
    /// assert!(!CountryCode::admits_fgi_trigraph(b"usa"));
    /// // Rejected: digit.
    /// assert!(!CountryCode::admits_fgi_trigraph(b"US1"));
    /// // Rejected: empty.
    /// assert!(!CountryCode::admits_fgi_trigraph(b""));
    /// ```
    #[inline]
    pub const fn admits_fgi_trigraph(bytes: &[u8]) -> bool {
        if bytes.len() != 3 {
            return false;
        }
        let mut i = 0;
        while i < 3 {
            if !bytes[i].is_ascii_uppercase() {
                return false;
            }
            i += 1;
        }
        true
    }

    /// FGI / REL TO list-token admission predicate: 2, 3, or 4 ASCII
    /// uppercase letters. This is the canonical shape gate for a
    /// single token in an FGI marker list, a REL TO list, or a JOINT
    /// `[LIST]` — wherever CAPCO's grammar admits a country trigraph,
    /// a tetragraph, or one of the registered 2-letter exception
    /// codes (notably `EU`, which the ISMCAT `CVEnumISMCATRelTo`
    /// surface emits as a 2-byte code).
    ///
    /// Returns `true` iff `bytes.len()` is `2`, `3`, or `4` and every
    /// byte is in `b'A'..=b'Z'`.
    ///
    /// Length rationale (the three accepted lengths):
    /// - `3` — Annex B GENC trigraph country codes (the bulk of FGI
    ///   and REL TO list tokens, e.g., `USA`, `GBR`, `DEU`).
    /// - `4` — Annex A tetragraph codes for international
    ///   organizations / alliances / coalitions (e.g., `NATO`,
    ///   `ISAF`, `FVEY`, `ACGU`, `TEYE`).
    /// - `2` — registered exception codes; `EU` is the canonical
    ///   case shipped in the ODNI ISMCAT `CVEnumISMCATRelTo` surface.
    ///
    /// Strictly broader than [`CountryCode::admits_fgi_trigraph`]
    /// (3-only), and strictly stricter than [`CountryCode::try_new`]
    /// (which also admits digits, underscore, and 5-byte+ codes).
    /// The 5-byte-plus codes that `try_new` admits — `AUSTRALIA_GROUP`
    /// in particular — are out of scope for this predicate; CAPCO-2016
    /// §H.7 calls these out as a separate surface ("unless an
    /// exception is granted") and the strict parser does not admit
    /// them in FGI/REL TO lists at this gate.
    ///
    /// Single source of truth for the shape gate at three call sites:
    /// `Vocabulary<CapcoScheme>::shape_admits(CAT_FGI_MARKER, _)`,
    /// `Vocabulary<CapcoScheme>::shape_admits(CAT_REL_TO, _)`, and
    /// the strict parser at
    /// `crates/core/src/parser.rs::parse_fgi_marker`. All three MUST
    /// go through this function rather than inline a length-and-class
    /// check — keeping the predicate single-sited prevents drift
    /// between admission and parser surfaces (CHK030, CHK026).
    ///
    /// Registry membership (whether a 2-letter code is `EU` vs. `US`,
    /// whether `NATO` / `FVEY` / `ABCD` is actually a registered
    /// Annex A tetragraph) is intentionally out of scope: shape
    /// admission ≠ registry validation. Registry membership is
    /// enforced at the rule layer (rules walk
    /// `marque_ism::TETRAGRAPH_MEMBERS` / `marque_ism::TRIGRAPHS`)
    /// and the rule-layer ordering invariant (trigraphs alphabetic,
    /// then tetragraphs alphabetic — §H.7 p122) is likewise a
    /// separate concern. This mirrors how `admits_fgi_trigraph`
    /// admits any 3 ASCII upper bytes, not only Annex B-registered
    /// codes.
    ///
    /// Authority: CAPCO-2016 §H.7 p122 ("Multiple FGI trigraph
    /// country codes or tetragraph codes must be separated by a
    /// single space ... A tetragraph is a four-letter code ... used
    /// to represent an international organization, alliance, or
    /// coalition. ... example may appear as: SECRET//FGI GBR JPN
    /// NATO//REL TO USA, GBR, JPN, NATO.") + §H.8 p150 (REL TO list
    /// admits the same shape) + §A.6 pp 16-17 (token-level grammar
    /// for foreign-disclosure list slots) + ODNI ISMCAT
    /// `CVEnumISMCATRelTo` (registered 2-byte exception codes
    /// including `EU`).
    ///
    /// # Examples
    ///
    /// ```
    /// use marque_ism::CountryCode;
    /// // Trigraphs admit.
    /// assert!(CountryCode::admits_country_token(b"USA"));
    /// assert!(CountryCode::admits_country_token(b"GBR"));
    /// // Tetragraphs admit (the §H.7 canonical example).
    /// assert!(CountryCode::admits_country_token(b"NATO"));
    /// assert!(CountryCode::admits_country_token(b"FVEY"));
    /// assert!(CountryCode::admits_country_token(b"ISAF"));
    /// // 2-letter exception codes admit (e.g., EU).
    /// assert!(CountryCode::admits_country_token(b"EU"));
    /// // Rejected: single letter.
    /// assert!(!CountryCode::admits_country_token(b"U"));
    /// // Rejected: too long.
    /// assert!(!CountryCode::admits_country_token(b"USAGB"));
    /// assert!(!CountryCode::admits_country_token(b"AUSTRALIA_GROUP"));
    /// // Rejected: lowercase trigraph, tetragraph, exception code.
    /// assert!(!CountryCode::admits_country_token(b"usa"));
    /// assert!(!CountryCode::admits_country_token(b"nato"));
    /// assert!(!CountryCode::admits_country_token(b"eu"));
    /// // Rejected: digit.
    /// assert!(!CountryCode::admits_country_token(b"US1"));
    /// assert!(!CountryCode::admits_country_token(b"NAT0"));
    /// // Rejected: empty.
    /// assert!(!CountryCode::admits_country_token(b""));
    /// ```
    #[inline]
    pub const fn admits_country_token(bytes: &[u8]) -> bool {
        let len = bytes.len();
        if len < 2 || len > 4 {
            return false;
        }
        let mut i = 0;
        while i < len {
            if !bytes[i].is_ascii_uppercase() {
                return false;
            }
            i += 1;
        }
        true
    }

    /// Shape-only predicate for FGI ownership context: admits any
    /// 2- or 3-byte ASCII-upper token (via
    /// [`CountryCode::admits_country_token`]) OR the literal `NATO`
    /// tetragraph. Other 4-byte tetragraphs (`CFIUS`, `FVEY`,
    /// `ACGU`, `ISAF`, etc.) are distribution-list markers per
    /// CAPCO-2016 §H.7 p122 — wrong semantic for FGI ownership, so
    /// the gate excludes them.
    ///
    /// # Shape-only by design
    ///
    /// This predicate does NOT validate against the `CountryCode`
    /// registry. Any shape-conformant 2- or 3-byte uppercase token
    /// will admit here, including unregistered ones like `XX`,
    /// `AB`, or `ZZZ`. Registry validation is the job of downstream
    /// rules (S004 trigraph-suggest, E008 unknown-token) per the
    /// established parser/rule split — the parser produces well-
    /// formed AST nodes; the rule layer flags unknown tokens with
    /// actionable diagnostics. This produces better UX than silent
    /// parser-level rejection (an unrecognized 3-byte token like
    /// `XYZ` lands as `Acknowledged([XYZ])` and a downstream rule
    /// can suggest the closest registered trigraph).
    ///
    /// # Why 2-byte admission
    ///
    /// The 2-byte branch is motivated by EU specifically: EU has
    /// its own classification system (EU CONFIDENTIAL / EU SECRET
    /// / EU TOP SECRET per Council Decision 2013/488/EU and
    /// successors) and is the only supranational sub-NATO entity
    /// that produces classified information today. EU also appears
    /// as a registered 2-letter exception code in ODNI ISMCAT
    /// `CVEnumISMCATRelTo`. The branch is shape-only rather than
    /// EU-only so the predicate stays composable with future
    /// 2-letter registrations without needing a parser edit.
    ///
    /// # Why not narrower
    ///
    /// This is narrower than [`CountryCode::admits_country_token`]
    /// (which admits any 2-4 char uppercase token) only on the
    /// tetragraph axis: distribution-list tetragraphs reject. FGI
    /// ownership semantic per §H.7 p122 places `NATO` as the only
    /// alliance tetragraph treated as an ownership identifier;
    /// `FVEY` / `CFIUS` / `ACGU` / `ISAF` describe who may receive
    /// a marking, not who owns it — they are lawful in REL TO list
    /// slots but not FGI ownership slots.
    ///
    /// # Decoder coordination
    ///
    /// Issue #496 tracks whether the decoder should add FGI-
    /// context-aware confidence-bounded country-code matching for
    /// unregistered uppercase tokens. If that lands, the parser
    /// side here does NOT need to change — the shape-only contract
    /// composes with decoder-side smartening.
    ///
    /// # Authority
    ///
    /// CAPCO-2016 §H.7 p122 (FGI as foreign-government ownership;
    /// banner-form `FGI [LIST]` where the list identifies the
    /// originating country/countries or NATO) + §H.7 p123 (banner-
    /// form table). The canonical multi-country example
    /// (`SECRET//FGI GBR JPN NATO//REL TO USA, GBR, JPN, NATO`)
    /// that places NATO in the FGI slot alongside sovereign-state
    /// trigraphs lives at §A.6 p16, not §H.7 p122 (p122 carries the
    /// ownership-semantic prose and the `FGI [LIST]` Register form;
    /// the list grammar with NATO is the §A.6 example). ODNI
    /// ISMCAT `CVEnumISMCATRelTo` registers `EU` as a 2-letter
    /// exception code; Council Decision 2013/488/EU (and
    /// successors) formalizes the EU classification system that
    /// gives EU-originated information ownership semantic. The
    /// asymmetry between this predicate and
    /// [`CountryCode::admits_country_token`] (REL TO list-tokens)
    /// is documented in this crate's parser at
    /// `crates/core/src/parser.rs::parse_fgi_marker`.
    ///
    /// # Examples
    ///
    /// ```
    /// use marque_ism::CountryCode;
    /// // 3-byte registered trigraphs admit.
    /// assert!(CountryCode::admits_fgi_ownership_token(b"USA"));
    /// assert!(CountryCode::admits_fgi_ownership_token(b"GBR"));
    /// assert!(CountryCode::admits_fgi_ownership_token(b"DEU"));
    /// // NATO admits — the only alliance tetragraph treated as
    /// // ownership per §H.7.
    /// assert!(CountryCode::admits_fgi_ownership_token(b"NATO"));
    /// // EU admits — its own classification system per Council
    /// // Decision 2013/488/EU; registered in ISMCAT
    /// // CVEnumISMCATRelTo. Drives the 2-byte admission branch.
    /// assert!(CountryCode::admits_fgi_ownership_token(b"EU"));
    /// // Shape-only: unregistered 2- and 3-byte uppercase tokens
    /// // also admit (downstream rules flag the registry miss).
    /// assert!(CountryCode::admits_fgi_ownership_token(b"XX"));
    /// assert!(CountryCode::admits_fgi_ownership_token(b"AB"));
    /// assert!(CountryCode::admits_fgi_ownership_token(b"ZZZ"));
    /// // Rejected: distribution-list tetragraphs (FVEY, CFIUS,
    /// // ACGU, ISAF) are REL TO surface, not FGI ownership.
    /// assert!(!CountryCode::admits_fgi_ownership_token(b"FVEY"));
    /// assert!(!CountryCode::admits_fgi_ownership_token(b"ACGU"));
    /// assert!(!CountryCode::admits_fgi_ownership_token(b"ISAF"));
    /// // Rejected: arbitrary 4-char tetragraphs.
    /// assert!(!CountryCode::admits_fgi_ownership_token(b"DEUX"));
    /// assert!(!CountryCode::admits_fgi_ownership_token(b"BLAH"));
    /// // Rejected: NAT0 (digit zero substituted for `O`) — the
    /// // 4-byte branch is a strict literal match against `NATO`,
    /// // not a fuzzy compare. Pins that the predicate does not
    /// // accidentally accept visually-similar candidates.
    /// assert!(!CountryCode::admits_fgi_ownership_token(b"NAT0"));
    /// // Rejected: lowercase (fails admits_country_token shape).
    /// assert!(!CountryCode::admits_fgi_ownership_token(b"eu"));
    /// assert!(!CountryCode::admits_fgi_ownership_token(b"usa"));
    /// assert!(!CountryCode::admits_fgi_ownership_token(b"nato"));
    /// // Rejected: wrong length (1-byte, 5+-byte).
    /// assert!(!CountryCode::admits_fgi_ownership_token(b""));
    /// assert!(!CountryCode::admits_fgi_ownership_token(b"U"));
    /// assert!(!CountryCode::admits_fgi_ownership_token(b"USAGB"));
    /// ```
    #[inline]
    pub const fn admits_fgi_ownership_token(bytes: &[u8]) -> bool {
        // NATO is the only valid tetragraph in FGI ownership context.
        if bytes.len() == 4 {
            return matches!(bytes, b"NATO");
        }
        // Otherwise must be a 2- or 3-byte ASCII-upper token. Shape-
        // only by design — any conformant token admits, including
        // unregistered ones like `XX` or `ZZZ` (see doc-comment §
        // "Shape-only by design"). Registry validation is the rule
        // layer's job (S004 / E008). `admits_country_token` enforces
        // uniform ASCII upper across 2..=4 byte lengths, so
        // lowercase, digits, and punctuation are rejected at this
        // site for both length branches.
        (bytes.len() == 2 || bytes.len() == 3) && Self::admits_country_token(bytes)
    }
}

impl std::fmt::Display for CountryCode {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.write_str(self.as_str())
    }
}

#[cfg(test)]
#[cfg_attr(coverage_nightly, coverage(off))]
mod country_code_tests {
    use super::CountryCode;

    #[test]
    fn try_new_accepts_two_byte_eu() {
        let eu = CountryCode::try_new(b"EU").unwrap();
        assert_eq!(eu.as_str(), "EU");
        assert_eq!(eu.len(), 2);
    }

    #[test]
    fn try_new_accepts_three_byte_trigraph() {
        let usa = CountryCode::try_new(b"USA").unwrap();
        assert_eq!(usa, CountryCode::USA);
        assert_eq!(usa.as_str(), "USA");
    }

    #[test]
    fn try_new_accepts_four_byte_tetragraph() {
        let fvey = CountryCode::try_new(b"FVEY").unwrap();
        assert_eq!(fvey.as_str(), "FVEY");
        assert_eq!(fvey.len(), 4);
    }

    #[test]
    fn try_new_accepts_australia_group_with_underscore() {
        let ag = CountryCode::try_new(b"AUSTRALIA_GROUP").unwrap();
        assert_eq!(ag.as_str(), "AUSTRALIA_GROUP");
        assert_eq!(ag.len(), 15);
    }

    #[test]
    fn try_new_accepts_digits_in_ax2_ax3() {
        assert_eq!(CountryCode::try_new(b"AX2").unwrap().as_str(), "AX2");
        assert_eq!(CountryCode::try_new(b"AX3").unwrap().as_str(), "AX3");
    }

    #[test]
    fn try_new_rejects_too_short() {
        assert!(CountryCode::try_new(b"").is_none());
        assert!(CountryCode::try_new(b"X").is_none());
    }

    #[test]
    fn try_new_rejects_too_long() {
        // 17 bytes — one over capacity.
        assert!(CountryCode::try_new(b"ABCDEFGHIJKLMNOPQ").is_none());
    }

    #[test]
    fn try_new_rejects_lowercase() {
        assert!(CountryCode::try_new(b"usa").is_none());
        assert!(CountryCode::try_new(b"Fvey").is_none());
    }

    #[test]
    fn try_new_rejects_non_ascii() {
        // 'É' is two UTF-8 bytes (0xC3 0x89); first byte fails the
        // is_valid_byte check.
        let bytes = "ÉU".as_bytes();
        assert!(CountryCode::try_new(bytes).is_none());
    }

    #[test]
    fn ord_matches_str_lex_for_mixed_lengths() {
        let eu = CountryCode::try_new(b"EU").unwrap();
        let aus = CountryCode::try_new(b"AUS").unwrap();
        let usa = CountryCode::USA;
        let usab = CountryCode::try_new(b"USAB").unwrap();
        let mut all = [eu, aus, usa, usab];
        all.sort();
        assert_eq!(all[0].as_str(), "AUS");
        assert_eq!(all[1].as_str(), "EU");
        assert_eq!(all[2].as_str(), "USA");
        assert_eq!(all[3].as_str(), "USAB");
    }

    #[test]
    fn copy_semantics_preserved() {
        let original = CountryCode::USA;
        let copy = original;
        // Both still usable — `Copy` not `Move`.
        assert_eq!(original, copy);
        assert_eq!(original.as_str(), copy.as_str());
    }

    #[test]
    fn display_renders_active_bytes_only() {
        // Display impl writes the active byte slice; the zero
        // padding past `len` must never reach the formatter.
        let usa = CountryCode::USA;
        let fvey = CountryCode::try_new(b"FVEY").unwrap();
        let ag = CountryCode::try_new(b"AUSTRALIA_GROUP").unwrap();
        assert_eq!(format!("{usa}"), "USA");
        assert_eq!(format!("{fvey}"), "FVEY");
        assert_eq!(format!("{ag}"), "AUSTRALIA_GROUP");
    }

    #[test]
    fn as_bytes_excludes_zero_padding() {
        let usa = CountryCode::USA;
        assert_eq!(usa.as_bytes(), b"USA");
        let fvey = CountryCode::try_new(b"FVEY").unwrap();
        assert_eq!(fvey.as_bytes(), b"FVEY");
    }

    #[test]
    fn is_empty_invariant_always_false() {
        // `try_new` rejects `len < 2`, so a constructed `CountryCode`
        // is never empty. `is_empty` exists only to satisfy clippy's
        // `len_without_is_empty`; pin the invariant so a future
        // refactor that loosens `try_new` is forced to revisit it.
        assert!(!CountryCode::USA.is_empty());
        assert!(!CountryCode::try_new(b"EU").unwrap().is_empty());
        assert!(!CountryCode::try_new(b"AUSTRALIA_GROUP").unwrap().is_empty());
    }

    #[test]
    fn usa_constant_matches_try_new() {
        // `pub const USA` constructs via `try_new` in const context.
        // Pin the equivalence so a future change to either path
        // (e.g., adding a normalization step to `try_new` but not
        // the const constructor) breaks loudly.
        let runtime = CountryCode::try_new(b"USA").unwrap();
        assert_eq!(CountryCode::USA, runtime);
        assert_eq!(CountryCode::USA.as_bytes(), runtime.as_bytes());
        assert_eq!(CountryCode::USA.len(), runtime.len());
    }

    #[test]
    fn nato_constant_matches_try_new() {
        // PR #505: `CountryCode::NATO` is forward-investment for the
        // NATO classification closure cone deferred to #508. Same
        // const-construction invariant as USA / AUS / CAN / GBR / NZL.
        let runtime = CountryCode::try_new(b"NATO").expect("NATO is a valid tetragraph");
        assert_eq!(CountryCode::NATO, runtime);
        assert_eq!(CountryCode::NATO.as_str(), "NATO");
        assert_eq!(CountryCode::NATO.as_bytes(), b"NATO");
        assert_eq!(CountryCode::NATO.len(), 4);
    }

    // ----------------------------------------------------------------
    // admits_fgi_trigraph — Annex B trigraph shape predicate
    // ----------------------------------------------------------------
    //
    // FR-015 / FR-016 closure: this predicate IS the documented FGI /
    // REL-TO trigraph admission gate. Both the `Vocabulary<CapcoScheme>`
    // adapter (`crates/capco/src/vocabulary.rs`) and the strict parser
    // (`crates/core/src/parser.rs`) call into it. These tests pin the
    // invariants both call sites depend on; a regression that loosens
    // the predicate (e.g., admitting digits, lowercase, or tetragraphs)
    // would silently broaden the accept set on both surfaces.

    #[test]
    fn admits_fgi_trigraph_accepts_three_uppercase_letters() {
        assert!(CountryCode::admits_fgi_trigraph(b"USA"));
        assert!(CountryCode::admits_fgi_trigraph(b"GBR"));
        assert!(CountryCode::admits_fgi_trigraph(b"DEU"));
        assert!(CountryCode::admits_fgi_trigraph(b"AUS"));
        assert!(CountryCode::admits_fgi_trigraph(b"JPN"));
    }

    #[test]
    fn admits_fgi_trigraph_rejects_lowercase() {
        assert!(!CountryCode::admits_fgi_trigraph(b"usa"));
        assert!(!CountryCode::admits_fgi_trigraph(b"Usa"));
        assert!(!CountryCode::admits_fgi_trigraph(b"USa"));
    }

    #[test]
    fn admits_fgi_trigraph_rejects_wrong_length() {
        assert!(!CountryCode::admits_fgi_trigraph(b""));
        assert!(!CountryCode::admits_fgi_trigraph(b"U"));
        assert!(!CountryCode::admits_fgi_trigraph(b"US"));
        assert!(!CountryCode::admits_fgi_trigraph(b"USAA"));
        // Tetragraphs (4-letter org codes) live in the separate
        // tetragraph table, not this trigraph predicate.
        assert!(!CountryCode::admits_fgi_trigraph(b"NATO"));
        assert!(!CountryCode::admits_fgi_trigraph(b"FVEY"));
        assert!(!CountryCode::admits_fgi_trigraph(b"ISAF"));
    }

    #[test]
    fn admits_fgi_trigraph_rejects_digits() {
        // `CountryCode::try_new` accepts ASCII digits (for AX2 / AX3),
        // but the FGI trigraph predicate does not — Annex B GENC codes
        // are alpha-only.
        assert!(!CountryCode::admits_fgi_trigraph(b"AX2"));
        assert!(!CountryCode::admits_fgi_trigraph(b"123"));
        assert!(!CountryCode::admits_fgi_trigraph(b"US1"));
    }

    #[test]
    fn admits_fgi_trigraph_rejects_underscore() {
        // `CountryCode::try_new` accepts underscore (for
        // AUSTRALIA_GROUP), but the FGI trigraph predicate rejects
        // every non-alpha byte.
        assert!(!CountryCode::admits_fgi_trigraph(b"US_"));
        assert!(!CountryCode::admits_fgi_trigraph(b"_US"));
    }

    #[test]
    fn admits_fgi_trigraph_rejects_non_ascii() {
        // 'É' is two UTF-8 bytes (0xC3 0x89); first byte is not ASCII
        // uppercase. A 3-byte UTF-8 sequence must still fail because
        // every byte must individually be in `b'A'..=b'Z'`.
        let two_byte_e_acute = "ÉU".as_bytes(); // 3 bytes total
        assert_eq!(two_byte_e_acute.len(), 3);
        assert!(!CountryCode::admits_fgi_trigraph(two_byte_e_acute));
    }

    #[test]
    fn admits_fgi_trigraph_implies_try_new() {
        // Property: if `admits_fgi_trigraph` accepts, then `try_new`
        // accepts (the trigraph predicate is strictly stronger). This
        // is what lets the parser gate by `admits_fgi_trigraph` and
        // construct via `try_new` without a redundant validation.
        for code in [b"USA", b"GBR", b"DEU", b"FRA", b"JPN"] {
            assert!(CountryCode::admits_fgi_trigraph(code));
            assert!(CountryCode::try_new(code).is_some());
        }
    }

    // -------------------------------------------------------------------
    // admits_country_token — full FGI/REL TO list-token shape predicate
    //
    // Per CAPCO-2016 §H.7 p122, the FGI list grammar admits BOTH 3-letter
    // Annex B trigraphs and 4-letter Annex A tetragraphs (canonical
    // example: `SECRET//FGI GBR JPN NATO`). The §H.8 REL TO surface
    // accepts the same shape. These tests pin the trigraph-or-tetragraph
    // contract so a regression to "trigraph-only" (PR #311 review
    // finding, GH #280 fix-cousin) is caught at unit-test scope.
    // -------------------------------------------------------------------

    #[test]
    fn admits_country_token_accepts_trigraphs() {
        assert!(CountryCode::admits_country_token(b"USA"));
        assert!(CountryCode::admits_country_token(b"GBR"));
        assert!(CountryCode::admits_country_token(b"DEU"));
        assert!(CountryCode::admits_country_token(b"AUS"));
        assert!(CountryCode::admits_country_token(b"JPN"));
    }

    #[test]
    fn admits_country_token_accepts_tetragraphs() {
        // Per CAPCO-2016 §H.7 p122 ("Multiple FGI trigraph country
        // codes or tetragraph codes must be separated by a single
        // space ... example may appear as: SECRET//FGI GBR JPN
        // NATO//REL TO USA, GBR, JPN, NATO."), tetragraphs admit at
        // the same shape gate as trigraphs.
        assert!(CountryCode::admits_country_token(b"NATO"));
        assert!(CountryCode::admits_country_token(b"FVEY"));
        assert!(CountryCode::admits_country_token(b"ISAF"));
        assert!(CountryCode::admits_country_token(b"ACGU"));
        assert!(CountryCode::admits_country_token(b"TEYE"));
    }

    #[test]
    fn admits_country_token_accepts_two_letter_exception() {
        // ODNI ISMCAT `CVEnumISMCATRelTo` ships `EU` as a registered
        // 2-letter exception code; pre-PR-2 REL TO admission accepted
        // it via the union TRIGRAPHS table. The shape gate must not
        // narrow that surface — registry membership of any 2-letter
        // code other than `EU` is a rule-layer concern, not a
        // shape concern.
        assert!(CountryCode::admits_country_token(b"EU"));
    }

    #[test]
    fn admits_country_token_rejects_lowercase() {
        assert!(!CountryCode::admits_country_token(b"usa"));
        assert!(!CountryCode::admits_country_token(b"nato"));
        assert!(!CountryCode::admits_country_token(b"Nato"));
        assert!(!CountryCode::admits_country_token(b"NaTO"));
        assert!(!CountryCode::admits_country_token(b"eu"));
        assert!(!CountryCode::admits_country_token(b"Eu"));
    }

    #[test]
    fn admits_country_token_rejects_digits() {
        assert!(!CountryCode::admits_country_token(b"US1"));
        assert!(!CountryCode::admits_country_token(b"NAT0")); // 0 not O
        assert!(!CountryCode::admits_country_token(b"123"));
        assert!(!CountryCode::admits_country_token(b"1234"));
        assert!(!CountryCode::admits_country_token(b"E1"));
    }

    #[test]
    fn admits_country_token_rejects_wrong_length() {
        assert!(!CountryCode::admits_country_token(b""));
        assert!(!CountryCode::admits_country_token(b"U"));
        // 5-letter+ codes (`AUSTRALIA_GROUP` is 15) explicitly
        // out of scope per the predicate's "exception is granted"
        // carve-out — these are admitted via `try_new`, not at
        // this gate.
        assert!(!CountryCode::admits_country_token(b"USAGB"));
        assert!(!CountryCode::admits_country_token(b"AUSTRALIA_GROUP"));
    }

    #[test]
    fn admits_country_token_rejects_underscore_and_punctuation() {
        // `try_new` admits underscore; this gate does not.
        assert!(!CountryCode::admits_country_token(b"US_"));
        assert!(!CountryCode::admits_country_token(b"NAT_"));
        assert!(!CountryCode::admits_country_token(b"USA "));
        assert!(!CountryCode::admits_country_token(b"USA-"));
        assert!(!CountryCode::admits_country_token(b"E_"));
    }

    #[test]
    fn admits_country_token_supersets_admits_fgi_trigraph() {
        // Property: every `admits_fgi_trigraph` accept is also an
        // `admits_country_token` accept. Pins the strictly-broader
        // contract so a future predicate edit can't silently invert
        // the relationship.
        for code in [&b"USA"[..], b"GBR", b"DEU", b"FRA", b"JPN", b"AUS", b"CAN"] {
            assert!(CountryCode::admits_fgi_trigraph(code));
            assert!(CountryCode::admits_country_token(code));
        }
    }
}

#[cfg(test)]
#[cfg_attr(coverage_nightly, coverage(off))]
mod sar_shape_tests {
    //! Shape-admission predicates for SAR program identifiers and
    //! compartments / sub-compartments. These are the canonical
    //! single-source-of-truth predicates that
    //! `crates/core/src/parser.rs::parse_sar_program` calls; the
    //! parser-side tests in `crates/core/src/parser.rs::sar_parse_tests`
    //! exercise the full grammar through the dispatch path. These
    //! tests focus on the predicate's accept/reject set in isolation.
    //!
    //! Authority: CAPCO-2016 §H.5 pp 99–101 (verified against
    //! `crates/capco/docs/CAPCO-2016.md`).

    use super::{SarCompartment, SarProgram};

    // ----- SarProgram::admits_program_id_abbrev -------------------------

    #[test]
    fn abbrev_accepts_two_or_three_alnum() {
        // §H.5 p101 register-convention examples.
        assert!(SarProgram::admits_program_id_abbrev(b"BP"));
        assert!(SarProgram::admits_program_id_abbrev(b"SDA"));
        assert!(SarProgram::admits_program_id_abbrev(b"XR"));
        // §H.5 p99 — alphanumeric values (digits permitted).
        assert!(SarProgram::admits_program_id_abbrev(b"A1"));
        assert!(SarProgram::admits_program_id_abbrev(b"99"));
        assert!(SarProgram::admits_program_id_abbrev(b"1A2"));
    }

    #[test]
    fn abbrev_rejects_wrong_length() {
        // Length < 2: empty or 1 char.
        assert!(!SarProgram::admits_program_id_abbrev(b""));
        assert!(!SarProgram::admits_program_id_abbrev(b"B"));
        // Length > 3: 4 chars or more.
        assert!(!SarProgram::admits_program_id_abbrev(b"BPCD"));
        assert!(!SarProgram::admits_program_id_abbrev(b"ABCDE"));
    }

    #[test]
    fn abbrev_rejects_lowercase_open_vocab_shape_is_validation() {
        // Issue #280: SAR has no CVE registry (`CVEnumISMSAR.xml`
        // intentionally empty per ODNI policy). With no registry to
        // validate against, the shape gate IS the validation. Per
        // CAPCO-2016 §A.6 p15 + §G.1 p36, all banner-line and
        // portion-mark Register entries are uppercase; SAR
        // identifiers must conform. Lowercase / mixed-case falls
        // through to the decoder, which handles demangling.
        assert!(!SarProgram::admits_program_id_abbrev(b"bp"));
        assert!(!SarProgram::admits_program_id_abbrev(b"sDa"));
        assert!(!SarProgram::admits_program_id_abbrev(b"Bp"));
    }

    #[test]
    fn abbrev_rejects_punctuation_and_whitespace() {
        // The hyphen is the program/compartment separator
        // (§H.5 p100); admitting it inside the abbreviation would
        // silently re-parse the marking.
        assert!(!SarProgram::admits_program_id_abbrev(b"B-"));
        assert!(!SarProgram::admits_program_id_abbrev(b"-B"));
        // Space is the sub-compartment separator (§H.5 p100); same
        // re-parse risk.
        assert!(!SarProgram::admits_program_id_abbrev(b"B P"));
        // Other punctuation has no role in the §H.5 grammar.
        assert!(!SarProgram::admits_program_id_abbrev(b"B."));
        assert!(!SarProgram::admits_program_id_abbrev(b"B/"));
    }

    #[test]
    fn abbrev_rejects_non_ascii() {
        // Non-ASCII multi-byte sequences make `bytes.len()` exceed
        // the 2-3 char gate immediately; the alnum test would also
        // reject them. Both gates fail loud rather than admitting
        // a multi-byte token.
        let two_byte_e_acute: &[u8] = "é".as_bytes();
        assert_eq!(two_byte_e_acute.len(), 2);
        assert!(!SarProgram::admits_program_id_abbrev(two_byte_e_acute));
    }

    // ----- SarProgram::admits_program_id_full ---------------------------

    #[test]
    fn full_accepts_uppercase_with_optional_spaces() {
        // §H.5 p101 canonical example.
        assert!(SarProgram::admits_program_id_full(b"BUTTER POPCORN"));
        // Single uppercase token also lawful.
        assert!(SarProgram::admits_program_id_full(b"SODA"));
        assert!(SarProgram::admits_program_id_full(b"A"));
        // Multiple-word nicknames.
        assert!(SarProgram::admits_program_id_full(b"ALPHA BETA GAMMA"));
    }

    #[test]
    fn full_rejects_lowercase() {
        assert!(!SarProgram::admits_program_id_full(b"butter popcorn"));
        assert!(!SarProgram::admits_program_id_full(b"BUTTER popcorn"));
        assert!(!SarProgram::admits_program_id_full(b"Butter Popcorn"));
    }

    #[test]
    fn full_rejects_digits() {
        // Digits are abbreviation territory — admitting them in the
        // full form blurs the §H.5 p101 distinction between the
        // two indicator forms.
        assert!(!SarProgram::admits_program_id_full(b"123"));
        assert!(!SarProgram::admits_program_id_full(b"BUTTER1"));
        assert!(!SarProgram::admits_program_id_full(b"BP1"));
    }

    #[test]
    fn full_rejects_hyphen() {
        // The first hyphen after the indicator literal always marks
        // the program/compartment boundary (§H.5 p100). Admitting
        // hyphens inside the nickname would silently re-parse a
        // marking like `BUTTER-POPCORN` as
        // `program=BUTTER, compartment=POPCORN`.
        assert!(!SarProgram::admits_program_id_full(b"BUTTER-POPCORN"));
        assert!(!SarProgram::admits_program_id_full(b"-BUTTER"));
        assert!(!SarProgram::admits_program_id_full(b"BUTTER-"));
    }

    #[test]
    fn full_rejects_empty_or_only_spaces() {
        assert!(!SarProgram::admits_program_id_full(b""));
        assert!(!SarProgram::admits_program_id_full(b" "));
        assert!(!SarProgram::admits_program_id_full(b"   "));
    }

    #[test]
    fn full_rejects_other_punctuation() {
        assert!(!SarProgram::admits_program_id_full(b"BUTTER.POPCORN"));
        assert!(!SarProgram::admits_program_id_full(b"BUTTER/POPCORN"));
        assert!(!SarProgram::admits_program_id_full(b"BUTTER_POPCORN"));
    }

    // ----- SarCompartment::admits_identifier ----------------------------

    #[test]
    fn compartment_accepts_alnum_any_length_at_least_one() {
        // §H.5 p100 Table 7 examples (compartments).
        assert!(SarCompartment::admits_identifier(b"J12"));
        assert!(SarCompartment::admits_identifier(b"K15"));
        assert!(SarCompartment::admits_identifier(b"YYY"));
        assert!(SarCompartment::admits_identifier(b"XRA"));
        // §H.5 p100 Table 7 examples (sub-compartments — same shape).
        assert!(SarCompartment::admits_identifier(b"J54"));
        assert!(SarCompartment::admits_identifier(b"456"));
        assert!(SarCompartment::admits_identifier(b"689"));
        assert!(SarCompartment::admits_identifier(b"RB"));
    }

    #[test]
    fn compartment_accepts_length_one() {
        // Manual is silent on a lower bound beyond ≥1; marque admits
        // single-character identifiers.
        assert!(SarCompartment::admits_identifier(b"A"));
        assert!(SarCompartment::admits_identifier(b"1"));
    }

    #[test]
    fn compartment_accepts_long_alnum() {
        // Manual is silent on an upper length bound; marque admits
        // length 1+. A future revision pinning a cap is a planned
        // migration at this predicate.
        assert!(SarCompartment::admits_identifier(b"ABCDEFGHIJ"));
        assert!(SarCompartment::admits_identifier(b"VERYLONGCOMPARTMENT123"));
    }

    #[test]
    fn compartment_rejects_lowercase_open_vocab_shape_is_validation() {
        // Issue #280: SAR open-vocab tightening (see
        // `abbrev_rejects_lowercase_open_vocab_shape_is_validation`
        // for the full rationale). The compartment / sub-compartment
        // predicate enforces the same Register-uppercase rule per
        // §A.6 p15 + §G.1 p36.
        assert!(!SarCompartment::admits_identifier(b"j12"));
        assert!(!SarCompartment::admits_identifier(b"yYy"));
        assert!(!SarCompartment::admits_identifier(b"blue42"));
    }

    #[test]
    fn compartment_rejects_empty() {
        assert!(!SarCompartment::admits_identifier(b""));
    }

    #[test]
    fn compartment_rejects_punctuation_and_whitespace() {
        // Hyphen is compartment separator (§H.5 p100), space is
        // sub-compartment separator. Admitting either would re-parse
        // the marking.
        assert!(!SarCompartment::admits_identifier(b"J-12"));
        assert!(!SarCompartment::admits_identifier(b"J 12"));
        // Other punctuation has no role in §H.5.
        assert!(!SarCompartment::admits_identifier(b"J.12"));
        assert!(!SarCompartment::admits_identifier(b"J_12"));
        assert!(!SarCompartment::admits_identifier(b"J/12"));
    }

    #[test]
    fn compartment_rejects_non_ascii() {
        let two_byte_e_acute: &[u8] = "é".as_bytes();
        assert!(!SarCompartment::admits_identifier(two_byte_e_acute));
        let three_byte_e_acute: &[u8] = "Ĵ12".as_bytes();
        assert!(!SarCompartment::admits_identifier(three_byte_e_acute));
    }

    // ----- Cross-predicate sanity ---------------------------------------

    #[test]
    fn abbrev_implies_compartment() {
        // Property: anything `admits_program_id_abbrev` admits is
        // also admitted by `admits_identifier` — the abbreviation
        // shape (2-3 uppercase-or-digit) is strictly within the
        // compartment shape (1+ uppercase-or-digit). Useful as a
        // sanity check that the two predicates don't drift apart on
        // character class. Issue #280 tightened both predicates to
        // reject lowercase; the strict-subset property still holds
        // over the new (uppercase + digit) character class.
        for input in [
            b"BP".as_slice(),
            b"SDA".as_slice(),
            b"99".as_slice(),
            b"A1".as_slice(),
            b"XR".as_slice(),
        ] {
            assert!(SarProgram::admits_program_id_abbrev(input));
            assert!(
                SarCompartment::admits_identifier(input),
                "compartment predicate must admit anything the \
                 abbreviation predicate admits (input={:?})",
                std::str::from_utf8(input).unwrap_or("<non-utf8>"),
            );
        }
    }
}

// ===========================================================================
// SCI structural types (spec 003-sci-compartments)
// ===========================================================================

/// A fully-parsed SCI category-block entry.
///
/// A banner or portion may carry multiple `SciMarking` entries separated by
/// `/` within one SCI category block (e.g., `//SI-G/TK-BLFH//`).
///
/// Construction is restricted to [`SciMarking::new`] (the struct is
/// `#[non_exhaustive]`) so new fields can be added without breaking the
/// parser.
#[non_exhaustive]
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SciMarking {
    /// The control-system anchor. One of the published bare control
    /// systems (see [`SciControlBare`]) or a structurally-parsed custom
    /// value.
    pub system: SciControlSystem,

    /// Compartments in source order. Sort-order validation is the concern
    /// of CAPCO rule E033 (not the parser).
    pub compartments: Box<[SciCompartment]>,

    /// If the `{system}-{first_compartment}` composite exactly matches an
    /// ODNI CVE value (e.g., `SI-G`, `HCS-P`, `TK-BLFH`), this records the
    /// matching [`SciControl`] variant. Only populated when the matching
    /// compartment has NO sub-compartments — sub-compartments imply the
    /// compound is a structural anchor rather than a CVE atom. `None`
    /// otherwise.
    pub canonical_enum: Option<SciControl>,
}

impl SciMarking {
    /// Construct a new `SciMarking`. Used by the parser (`marque-core`) to
    /// populate [`CanonicalAttrs::sci_markings`].
    pub fn new(
        system: SciControlSystem,
        compartments: Box<[SciCompartment]>,
        canonical_enum: Option<SciControl>,
    ) -> Self {
        Self {
            system,
            compartments,
            canonical_enum,
        }
    }
}

/// Which kind of SCI control system a [`SciMarking`] anchors on.
///
/// One of three variants: a published bare system drawn from the live
/// ODNI CVE, an agency-allocated custom identifier (per CAPCO-2016
/// §A.6 p15), or a NATO Special Access Program identifier (CAPCO-2016
/// §G.2 p40 + §H.7 p127).
///
/// NATO SAPs (`BOHEMIA`, `BALK`) are not in the ODNI ISM CVE — they're
/// CAPCO-only registered NATO control markings. They render standalone
/// in their own `//`-separated category (in the SCI block position),
/// e.g. `//CTS//BOHEMIA` (banner) / `(//CTS//BOHEMIA)` (portion). See
/// the §H.7 p127 worked example for ordering: US class // US-SCI /
/// BALK / BOHEMIA // ... .
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum SciControlSystem {
    /// One of the published bare control systems.
    Published(SciControlBare),
    /// An agency-allocated system matching `[A-Z0-9]{2,5}` (per CAPCO-2016
    /// §A.6 p15 `123` example). Stores the raw text exactly as it appeared
    /// in the source.
    Custom(SmolStr),
    /// One of the two NATO Special Access Programs registered in
    /// CAPCO-2016 §G.2 p40 (`BOHEMIA`, `BALK`). NATO SAPs travel in
    /// the SCI category position but are CAPCO-only (no ODNI CVE
    /// entry).
    NatoSap(NatoSap),
}

/// Registered NATO Special Access Programs per CAPCO-2016 §G.2 p40 +
/// §H.7 Appendix B.
///
/// Both `Bohemia` and `Balk` render standalone (no `SAR-` prefix) and
/// are typically CTS-only. The §H.7 p127 worked example renders BALK
/// before BOHEMIA when both are present (numeric-then-alpha ordering
/// per §A.6 p15-16; `BALK < BOHEMIA` lexicographically).
/// Derive `Ord` so [`SciControlSystem::NatoSap`] participates in the
/// numeric-then-alpha ordering used by `PageContext::expected_sci_markings`
/// roll-up via `SystemKey`. The variants are declared `Balk` then
/// `Bohemia` (alphabetical text), so the derived `Ord` orders `Balk <
/// Bohemia` — which matches `as_str()`-based lexicographic ordering.
/// `as_str()` text remains the sort key consulted by the renderer and
/// roll-up; the derived `Ord` is a co-monotone alignment, not a
/// separate canonical order.
#[non_exhaustive]
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum NatoSap {
    /// BALK — NATO SAP per CAPCO-2016 §G.2 p40 (exercise replacement
    /// for BOHEMIA per legacy Combined Communications-Electronics
    /// Board guidance referenced in §G.2). BALK sorts before BOHEMIA
    /// alphabetically — see the §H.7 p127 worked example.
    Balk,
    /// BOHEMIA — NATO SAP per CAPCO-2016 §G.2 p40.
    Bohemia,
}

impl NatoSap {
    /// Canonical name as used in both banner and portion forms
    /// (CAPCO-2016 §G.1 Table 4 p38 row "ATOMAL/BALK/BOHEMIA" — same-
    /// form across title, banner-abbrev, and portion columns).
    pub fn as_str(self) -> &'static str {
        match self {
            Self::Bohemia => "BOHEMIA",
            Self::Balk => "BALK",
        }
    }
}

/// A single compartment under an SCI control system.
///
/// Compartments carry an identifier plus zero or more sub-compartments in
/// source order. Construction is restricted to [`SciCompartment::new`]
/// (the struct is `#[non_exhaustive]`).
#[non_exhaustive]
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SciCompartment {
    /// Compartment identifier (alphanumeric). Example: `G` in `SI-G`.
    pub identifier: SmolStr,
    /// Sub-compartments in source order. Example: `ABCD`, `DEFG` in
    /// `SI-G ABCD DEFG`.
    pub sub_compartments: Box<[SmolStr]>,
}

impl SciCompartment {
    /// Construct a new `SciCompartment`. Used by the parser to populate
    /// [`SciMarking::compartments`].
    pub fn new(identifier: impl Into<SmolStr>, sub_compartments: Box<[SmolStr]>) -> Self {
        Self {
            identifier: identifier.into(),
            sub_compartments,
        }
    }
}

#[cfg(test)]
#[cfg_attr(coverage_nightly, coverage(off))]
mod tests {
    use super::*;
    use crate::canonical::CanonicalAttrs;

    #[test]
    fn classification_ord_is_restrictiveness() {
        assert!(Classification::Unclassified < Classification::Restricted);
        assert!(Classification::Restricted < Classification::Confidential);
        assert!(Classification::Confidential < Classification::Secret);
        assert!(Classification::Secret < Classification::TopSecret);
    }

    #[test]
    fn classification_banner_portion_round_trip() {
        for c in [
            Classification::Unclassified,
            Classification::Restricted,
            Classification::Confidential,
            Classification::Secret,
            Classification::TopSecret,
        ] {
            assert!(!c.banner_str().is_empty());
            assert!(!c.portion_str().is_empty());
        }
    }

    #[test]
    fn nato_us_equivalent_mapping() {
        assert_eq!(
            NatoClassification::CosmicTopSecret.us_equivalent(),
            Classification::TopSecret,
        );
        assert_eq!(
            NatoClassification::NatoSecret.us_equivalent(),
            Classification::Secret,
        );
        assert_eq!(
            NatoClassification::NatoRestricted.us_equivalent(),
            Classification::Restricted,
        );
    }

    /// PR 9c.1 T134: `NatoClassification` is now a 5-variant bare-class
    /// enum; the 5 fused variants (`NatoConfidentialAtomal`,
    /// `NatoSecretAtomal`, `CosmicTopSecretAtomal`,
    /// `CosmicTopSecretBohemia`, `CosmicTopSecretBalk`) were retired
    /// because they conflated classification with AEA/SCI sub-marking
    /// semantics. ATOMAL now lives in [`AeaMarking::Atomal`];
    /// BALK/BOHEMIA in [`SciControlSystem::NatoSap`].
    #[test]
    fn nato_banner_portion_round_trip() {
        for n in [
            NatoClassification::NatoUnclassified,
            NatoClassification::NatoRestricted,
            NatoClassification::NatoConfidential,
            NatoClassification::NatoSecret,
            NatoClassification::CosmicTopSecret,
        ] {
            assert!(!n.banner_str().is_empty());
            assert!(!n.portion_str().is_empty());
        }
    }

    #[test]
    fn us_classification_convenience_returns_us() {
        let attrs = CanonicalAttrs {
            classification: Some(MarkingClassification::Us(Classification::Secret)),
            ..Default::default()
        };
        assert_eq!(attrs.us_classification(), Some(Classification::Secret));
    }

    #[test]
    fn us_classification_convenience_returns_none_for_nato() {
        let attrs = CanonicalAttrs {
            classification: Some(MarkingClassification::Nato(NatoClassification::NatoSecret)),
            ..Default::default()
        };
        assert_eq!(attrs.us_classification(), None);
    }

    #[test]
    fn us_classification_convenience_returns_resolved_for_conflict() {
        let attrs = CanonicalAttrs {
            classification: Some(MarkingClassification::Conflict {
                us: Classification::TopSecret,
                foreign: Box::new(ForeignClassification::Nato(
                    NatoClassification::CosmicTopSecret,
                )),
            }),
            ..Default::default()
        };
        assert_eq!(attrs.us_classification(), Some(Classification::TopSecret));
    }
}
